import { useState, useEffect } from "react";
import { apiGet } from "../../api";
import { LoadingRow, ErrorBanner, EmptyState, SideSheet } from "../../components";

type FrameworkSlug = "iso27001-2022" | "soc2-2017" | "nist-csf-2.0" | "gdpr" | "hipaa-security-rule";

const FRAMEWORKS: { slug: FrameworkSlug; label: string }[] = [
  { slug: "iso27001-2022", label: "ISO/IEC 27001:2022" },
  { slug: "soc2-2017", label: "SOC 2 (Trust Services Criteria)" },
  { slug: "nist-csf-2.0", label: "NIST CSF 2.0" },
  { slug: "gdpr", label: "GDPR Article 32" },
  { slug: "hipaa-security-rule", label: "HIPAA Security Rule" },
];

export interface ComplianceAttestation {
  id: string;
  customer_id: string;
  framework: string;
  period_start: string;
  period_end: string;
  attested_by_account_id: string | null;
  attested_role: string;
  attested_name: string;
  statement: string;
  bundle_sha256: string;
  signature: string;
  signature_algo: string;
  created_at: string;
}

export function AttestationsList({ customerId }: { customerId: string }) {
  const [selectedFramework, setSelectedFramework] = useState<FrameworkSlug>("iso27001-2022");
  const [attestations, setAttestations] = useState<ComplianceAttestation[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [selectedAttestation, setSelectedAttestation] = useState<ComplianceAttestation | null>(null);

  useEffect(() => {
    if (!customerId) return;
    setIsLoading(true);
    setError(null);
    apiGet<ComplianceAttestation[]>(`/compliance/attestations?customer_id=${customerId}&framework=${selectedFramework}`)
      .then(setAttestations)
      .catch((err: any) => setError(err.message || "Failed to load attestations."))
      .finally(() => setIsLoading(false));
  }, [customerId, selectedFramework]);

  return (
    <div className="no-print">
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "16px" }}>
        <p style={{ margin: "0", color: "var(--muted)", fontSize: "14px" }}>
          Read-only view of formal audit sign-offs and automatic attestations.
        </p>
        <div style={{ display: "flex", gap: "12px", alignItems: "center" }}>
          <label style={{ fontSize: "12px", fontWeight: "600", color: "var(--muted)" }}>Filter by Framework:</label>
          <select
            value={selectedFramework}
            onChange={(e) => setSelectedFramework(e.target.value as FrameworkSlug)}
            className="txt"
            style={{ padding: "8px 12px", borderRadius: "5px", background: "var(--bg-card)", border: "1px solid var(--border)", color: "var(--foreground)" }}
          >
            {FRAMEWORKS.map(f => (
              <option key={f.slug} value={f.slug}>{f.label}</option>
            ))}
          </select>
        </div>
      </div>

      {error && <ErrorBanner message={error} />}

      {isLoading ? (
        <LoadingRow label="Loading attestations..." />
      ) : attestations.length === 0 ? (
        <EmptyState>No formal system attestations signed yet for this framework.</EmptyState>
      ) : (
        <div className="panel" style={{ border: "1px solid var(--border)", borderRadius: "8px", overflow: "hidden" }}>
          <table className="table" style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead>
              <tr style={{ background: "var(--bg-thead)", borderBottom: "1px solid var(--border)", textAlign: "left" }}>
                <th style={{ padding: "12px" }}>Framework</th>
                <th style={{ padding: "12px" }}>Date Created</th>
                <th style={{ padding: "12px" }}>Period</th>
                <th style={{ padding: "12px" }}>Attested By</th>
                <th style={{ padding: "12px" }}>Bundle SHA-256</th>
                <th style={{ padding: "12px", textAlign: "right" }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {attestations.map((att) => (
                <tr key={att.id} style={{ borderBottom: "1px solid var(--border)" }}>
                  <td style={{ padding: "12px", fontSize: "13px", fontWeight: "600" }}>
                    {FRAMEWORKS.find(f => f.slug === att.framework)?.label || att.framework}
                  </td>
                  <td style={{ padding: "12px", fontSize: "13px" }}>
                    {new Date(att.created_at).toLocaleDateString()}
                  </td>
                  <td style={{ padding: "12px", fontSize: "13px", color: "var(--muted)" }}>
                    {att.period_start} to {att.period_end}
                  </td>
                  <td style={{ padding: "12px", fontSize: "13px" }}>
                    <div style={{ fontWeight: "600" }}>{att.attested_name}</div>
                    <div style={{ fontSize: "11px", color: "var(--muted)" }}>{att.attested_role}</div>
                  </td>
                  <td style={{ padding: "12px" }}>
                    <code style={{ fontSize: "11px", color: "var(--brand-primary)", background: "rgba(11, 107, 87, 0.1)", padding: "4px 8px", borderRadius: "4px" }}>
                      {att.bundle_sha256.substring(0, 16)}...
                    </code>
                  </td>
                  <td style={{ padding: "12px", textAlign: "right" }}>
                    <button
                      type="button"
                      className="btn"
                      onClick={() => setSelectedAttestation(att)}
                      style={{ padding: "4px 8px", fontSize: "12px" }}
                    >
                      View details
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {selectedAttestation && (
        <SideSheet
          open={!!selectedAttestation}
          onClose={() => setSelectedAttestation(null)}
          title="Attestation Details"
          subtitle="Full cryptographic signature and formal statement."
        >
          <div style={{ display: "flex", flexDirection: "column", gap: "20px" }}>
            <div>
              <h4 style={{ margin: "0 0 6px", fontSize: "13px", color: "var(--muted)" }}>Statement</h4>
              <div style={{ background: "var(--bg-card)", padding: "12px", borderRadius: "6px", border: "1px solid var(--border)", fontSize: "14px" }}>
                {selectedAttestation.statement}
              </div>
            </div>

            <div>
              <h4 style={{ margin: "0 0 6px", fontSize: "13px", color: "var(--muted)" }}>Bundle SHA-256</h4>
              <code style={{ display: "block", background: "var(--bg-thead)", padding: "12px", borderRadius: "6px", border: "1px solid var(--border)", fontSize: "12px", wordBreak: "break-all" }}>
                {selectedAttestation.bundle_sha256}
              </code>
            </div>

            <div>
              <h4 style={{ margin: "0 0 6px", fontSize: "13px", color: "var(--muted)" }}>Cryptographic Signature</h4>
              <code style={{ display: "block", background: "var(--bg-thead)", padding: "12px", borderRadius: "6px", border: "1px solid var(--border)", fontSize: "12px", wordBreak: "break-all" }}>
                {selectedAttestation.signature}
              </code>
              <p style={{ margin: "6px 0 0", fontSize: "11px", color: "var(--muted)" }}>Algorithm: {selectedAttestation.signature_algo}</p>
            </div>

            <div style={{ display: "flex", justifyContent: "flex-end", borderTop: "1px solid var(--border)", paddingTop: "16px" }}>
              <button
                type="button"
                className="btn"
                onClick={() => setSelectedAttestation(null)}
              >
                Close
              </button>
            </div>
          </div>
        </SideSheet>
      )}
    </div>
  );
}

import React from "react";
import { Terminal, User, Cpu } from "lucide-react";
import { Detection } from "./types";
import { EmptyState } from "./EmptyState";

interface DetailPanelProps {
  detection: Detection | null;
  /** Custom renderer for specific contexts (e.g. custom tree view, network connections, complex config). */
  customContextRenderer?: (detection: Detection) => React.ReactNode;
}

export function DetailPanel({ detection, customContextRenderer }: DetailPanelProps) {
  if (!detection) {
    return (
      <article className="panel" style={{ flex: 1, display: "flex", flexDirection: "column", minWidth: "300px" }}>
        <div className="panelHeader" style={{ paddingBottom: "12px", borderBottom: "1px solid var(--line)" }}>
          <div>
            <h2 style={{ fontSize: "16px", margin: 0 }}>Incident Context & Analysis</h2>
            <span style={{ fontSize: "12px", color: "var(--muted)" }}>No alert selected</span>
          </div>
        </div>
        <div style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", padding: "16px" }}>
          <EmptyState message="Select an item from the detections list on the left to inspect detail telemetry, MITRE mappings, and associated process logs." />
        </div>
      </article>
    );
  }

  const { context } = detection;

  return (
    <article className="panel" style={{ flex: 1, display: "flex", flexDirection: "column", minWidth: "300px" }}>
      <div className="panelHeader" style={{ paddingBottom: "12px", borderBottom: "1px solid var(--line)", marginBottom: "16px" }}>
        <div>
          <h2 style={{ fontSize: "16px", margin: 0 }}>Incident Context & Analysis</h2>
          <span style={{ fontSize: "12px", color: "var(--muted)" }}>Threat telemetry for {detection.endpoint_name}</span>
        </div>
      </div>

      <div style={{ flex: 1, overflowY: "auto", display: "flex", flexDirection: "column", gap: "20px" }}>
        {/* Threat summary */}
        <div style={{ padding: "12px", borderRadius: "8px", border: "1px solid var(--line)", background: "rgba(11, 107, 87, 0.01)" }}>
          <h3 style={{ margin: "0 0 6px 0", fontSize: "13px", color: "var(--accent)", fontWeight: 600 }}>AI Threat Summary</h3>
          <p style={{ margin: 0, fontSize: "12px", color: "var(--ink)", lineHeight: 1.5 }}>
            {detection.description}
          </p>
        </div>

        {/* Custom Context or Standard Metadata Fallback */}
        {customContextRenderer ? (
          customContextRenderer(detection)
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
            {/* Standard Key Properties */}
            <div>
              <h4 style={{ margin: "0 0 10px 0", fontSize: "12px", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.05em", color: "var(--muted)" }}>
                Execution Properties
              </h4>
              <div style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", fontSize: "12px" }}>
                  <span style={{ color: "var(--muted)", display: "inline-flex", alignItems: "center", gap: "6px" }}>
                    <Cpu size={14} /> Process
                  </span>
                  <strong style={{ color: "var(--ink)" }}>{detection.recommended_action === "kill_process" ? detection.title : "N/A"}</strong>
                </div>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", fontSize: "12px" }}>
                  <span style={{ color: "var(--muted)", display: "inline-flex", alignItems: "center", gap: "6px" }}>
                    <User size={14} /> Account Scope
                  </span>
                  <strong style={{ color: "var(--ink)" }}>{context?.user || "NT AUTHORITY\\SYSTEM"}</strong>
                </div>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", fontSize: "12px" }}>
                  <span style={{ color: "var(--muted)", display: "inline-flex", alignItems: "center", gap: "6px" }}>
                    <Terminal size={14} /> Launcher Command
                  </span>
                  <code style={{ background: "rgba(19, 32, 27, 0.04)", padding: "2px 4px", borderRadius: "4px", fontSize: "11px", maxWidth: "200px", overflow: "hidden", textOverflow: "ellipsis" }}>
                    {context?.command_line || "sh -c 'execute'"}
                  </code>
                </div>
              </div>
            </div>

            {/* Hashes / Config section */}
            {context?.file_hashes && context.file_hashes.length > 0 && (
              <div>
                <h4 style={{ margin: "0 0 8px 0", fontSize: "12px", fontWeight: 600, textTransform: "uppercase", color: "var(--muted)" }}>
                  Payload Analysis
                </h4>
                <div style={{ display: "flex", flexDirection: "column", gap: "6px", background: "rgba(11, 107, 87, 0.02)", padding: "8px", borderRadius: "6px", border: "1px solid var(--line)" }}>
                  {context.file_hashes.map((hash: any, i: number) => (
                    <div key={i} style={{ fontSize: "11px", display: "flex", flexDirection: "column", gap: "2px" }}>
                      <span style={{ color: "var(--muted)", fontWeight: 600 }}>{hash.algorithm.toUpperCase()}:</span>
                      <code style={{ wordBreak: "break-all", background: "#ffffff", padding: "4px", borderRadius: "4px", border: "1px solid var(--line)" }}>{hash.value}</code>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* MITRE Mapping */}
            {context?.mitre_techniques && context.mitre_techniques.length > 0 && (
              <div>
                <h4 style={{ margin: "0 0 8px 0", fontSize: "12px", fontWeight: 600, textTransform: "uppercase", color: "var(--muted)" }}>
                  MITRE ATT&CK Mappings
                </h4>
                <div style={{ display: "flex", flexWrap: "wrap", gap: "6px" }}>
                  {context.mitre_techniques.map((tech: any) => (
                    <span
                      key={tech.id}
                      style={{
                        background: "rgba(180, 80, 24, 0.08)",
                        color: "var(--warning)",
                        border: "1px solid rgba(180, 80, 24, 0.2)",
                        padding: "2px 8px",
                        borderRadius: "4px",
                        fontSize: "11px",
                        fontWeight: 600,
                      }}
                      title={`${tech.tactic}: ${tech.name}`}
                    >
                      {tech.id} - {tech.name}
                    </span>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </article>
  );
}

import type { RiskBand } from "../../api";

export type ModuleStatus = "protected" | "review_needed" | "disabled" | "planned";

export type DetectionStatus = "new" | "investigating" | "staged" | "resolved";

export type ActionStatus = "queued" | "awaiting_approval" | "approved" | "failed";

export interface Detection {
  id: string;
  customer_id?: string | null;
  endpoint_id: string | null;
  endpoint_name: string;
  title: string;
  source: string;
  description: string;
  risk_score: number;
  risk_band: RiskBand;
  confidence: number;
  recommended_action: string;
  status: DetectionStatus;
  created_at: string;
  context?: Record<string, any>;
}

export interface StagedAction {
  id: string;
  detection_id: string;
  action: string;
  status: ActionStatus;
  approval_required: boolean;
  requested_by: string;
  created_at: string;
  note?: string | null;
}

export interface SimulationPreview {
  id: string;
  detection_id: string;
  action: string;
  destructive: boolean;
  approval_required: boolean;
  estimated_impact: string[];
  affected_systems: number;
  evidence_controls?: string[];
  created_at: string;
}

export interface EffectivePolicy {
  policy_version: string;
  last_updated: string;
  status: ModuleStatus;
  approval_required: boolean;
  controls: Record<string, boolean>;
}

export interface ExclusionsList {
  id: string;
  pattern: string;
  type: string;
  reason: string;
}

