  severity: "low" | "medium" | "high" | "critical";
  affected_endpoints: string[];
  related_events: number;
  mitre_tactics: string[];
  recommended_response: string;
  steps: InvestigationStep[];
  created_at: string;
  updated_at: string;
  resolved_at?: string | null;
}

