  id: string;
  customer_id?: string | null;
  kind: BlocklistEntryKind;
  value: string;
  description: string;
  severity: "low" | "medium" | "high" | "critical";
  status: "active" | "review" | "disabled";
  added_by: string;
  created_at: string;
  hit_count: number;
  last_triggered?: string | null;
}

