import { FormEvent, useEffect, useRef, useState } from "react";
import { ExternalLink, ScanText } from "lucide-react";
import { apiGet, apiPost } from "../api";
import type { Alert, DlpScanResponse, Endpoint } from "../api";
import { ErrorBanner, LoadingRow, EmptyState, RiskBadge, ActionBadge, PageHeader } from "../components";
import { timeAgo } from "../utils";

export function DlpScanPage() {
  const [endpoints, setEndpoints] = useState<Endpoint[]>([]);
  const [scanHistory, setScanHistory] = useState<Alert[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [scanText, setScanText] = useState("");
  const [scanEndpointId, setScanEndpointId] = useState("");
  const [scanResult, setScanResult] = useState<DlpScanResponse | null>(null);
  const [isScanning, setIsScanning] = useState(false);

  const mountedRef = useRef(true);

  async function loadContext() {
    try {
      const [eps, allAlerts] = await Promise.all([
        apiGet<Endpoint[]>("/endpoints"),
        apiGet<Alert[]>("/alerts"),
      ]);
      if (mountedRef.current) {
        setEndpoints(eps);
        // Show alerts that originated from DLP scans
        setScanHistory(allAlerts.filter((a) => a.entity_types.length > 0 || a.source.toLowerCase().includes("scan")));
        setError(null);
      }
    } catch (err) {
      if (mountedRef.current) {
        setError(err instanceof Error ? err.message : "Failed to load context");
      }
    } finally {
      if (mountedRef.current) setIsLoading(false);
    }
  }

  useEffect(() => {
    mountedRef.current = true;
    void loadContext();
    return () => { mountedRef.current = false; };

  }, []);

  const resolvedEndpointId = endpoints.some((e) => e.id === scanEndpointId) ? scanEndpointId : "";

  async function runScan(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setIsScanning(true);
    setScanResult(null);
    setError(null);

    try {
      const result = await apiPost<DlpScanResponse>("/dlp/scan", {
        text: scanText,
        endpoint_id: resolvedEndpointId || null,
        source: "console manual scan",
      });
      setScanResult(result);
      await loadContext();
    } catch (err) {
      setError(err instanceof Error ? err.message : "DLP scan failed");
    } finally {
      setIsScanning(false);
    }
  }

  return (
    <>
      <PageHeader
        eyebrow="Data loss prevention"
        title="DLP Scanner"
        subtitle="Inspect text for protected entities using the active policy"
      />

      {error ? <ErrorBanner message={error} /> : null}

      {/* Scanner */}
      <section className="panel scanner">
        <div className="panelHeader">
          <div>
            <h2>Scan Content</h2>
            <span>Submit text to run it through the active DLP policy</span>
          </div>
          <ScanText aria-hidden="true" />
        </div>

        <form onSubmit={runScan}>
          <label>
            <span>Endpoint</span>
            <select
              value={resolvedEndpointId}
              onChange={(e) => setScanEndpointId(e.target.value)}
            >
              <option value="">Unassigned manual scan</option>
              {endpoints.map((ep) => (
                <option key={ep.id} value={ep.id}>
                  {ep.hostname}
                </option>
              ))}
            </select>
          </label>
          <textarea
            aria-label="Text to scan for protected data"
            placeholder="Paste text to inspect for protected data…"
            value={scanText}
            onChange={(e) => setScanText(e.target.value)}
          />
          <button disabled={isScanning || scanText.trim().length === 0}>
            {isScanning ? "Scanning…" : "Scan content"}
          </button>
        </form>

        {scanResult ? (
          <div className="findings">
            {/* Assessment summary */}
            <article className={`assessment band-${scanResult.risk_band}`}>
              <header>
                <strong>Risk assessment</strong>
                <div style={{ display: "flex", gap: "8px", alignItems: "center" }}>
                  <ActionBadge action={scanResult.action} />
                  <RiskBadge band={scanResult.risk_band} />
                </div>
              </header>
              <p>Score {scanResult.risk_score}/100</p>
              {scanResult.rationale ? <small>{scanResult.rationale}</small> : null}
              {scanResult.context_signals.length > 0 ? (
                <ul className="signals">
                  {scanResult.context_signals.map((s) => (
                    <li key={s}>{s.replaceAll("_", " ")}</li>
                  ))}
                </ul>
              ) : null}
            </article>

            {/* Finding cards */}
            {scanResult.findings.map((f) => (
              <article
                className="finding"
                key={`${f.entity_type}-${f.start}-${f.end}`}
              >
                <strong>{f.entity_type.replaceAll("_", " ")}</strong>
                <span>{f.text}</span>
                <small>{Math.round(f.score * 100)}% confidence</small>
              </article>
            ))}
            {scanResult.findings.length === 0 ? (
              <p style={{ gridColumn: "1/-1", margin: 0, color: "var(--muted)" }}>
                No protected entities detected.
              </p>
            ) : null}
          </div>
        ) : null}
      </section>

      {/* Scan history */}
      <section className="panel" style={{ marginTop: "18px" }}>
        <div className="panelHeader">
          <h2>Scan Event History</h2>
          <span>{scanHistory.length} DLP events</span>
        </div>

        <div className="endpointList">
          {scanHistory.slice(0, 20).map((alert) => (
            <article className="endpoint" key={alert.id} style={{ gridTemplateColumns: "1fr auto auto" }}>
              <div>
                <strong
                  className="linkLike"
                  role="button"
                  tabIndex={0}
                  onClick={() => window.dispatchEvent(new CustomEvent("aetherix:navigate", { detail: { page: "alerts" } }))}
                  onKeyDown={(e) => { if (e.key === "Enter") window.dispatchEvent(new CustomEvent("aetherix:navigate", { detail: { page: "alerts" } })); }}
                >
                  {alert.title} <ExternalLink size={12} />
                </strong>
                <p>
                  {alert.source} · {timeAgo(alert.created_at)}
                </p>
                {alert.entity_types.length > 0 ? (
                  <div className="signals" style={{ marginTop: "6px" }}>
                    {alert.entity_types.map((e) => (
                      <li key={e}>{e.replaceAll("_", " ")}</li>
                    ))}
                  </div>
                ) : null}
              </div>
              <span className={alert.status === "open" ? "attention" : "healthy"}>
                {alert.status}
              </span>
            </article>
          ))}
          {isLoading ? <LoadingRow label="Loading scan history" /> : null}
          {!isLoading && scanHistory.length === 0 ? (
            <EmptyState>No DLP scan events recorded yet.</EmptyState>
          ) : null}
        </div>
      </section>
    </>
  );
}

import React, { useState, useEffect } from "react";
import { Eye, Globe, Shield, AlertTriangle, Package, RefreshCw } from "lucide-react";
import { ModuleHeader } from "../components/protection/ModuleHeader";
import { DetectionTable } from "../components/protection/DetectionTable";
import { DetailPanel } from "../components/protection/DetailPanel";
import { ActionStagingPanel } from "../components/protection/ActionStagingPanel";
import { LoadingState } from "../components/protection/EmptyState";
import { Detection, StagedAction, SimulationPreview, EffectivePolicy } from "../components/protection/types";
import { ConsolePage, ErrorBanner, MetricGrid, SuccessBanner } from "../components";
import { apiGet, apiPost, type MeResponse } from "../api";

export interface DRPFinding {
  id: string;
  customer_id?: string | null;
  asset_id: string;
  asset_display_name: string;
  asset_type: "brand" | "executive" | "domain" | "social_account" | "repository" | "keyword";
  finding_type: "impersonation" | "typosquatting" | "homoglyph" | "phishing" | "credential_harvesting" | "brand_abuse" | "trademark_infringement" | "data_leak" | "compromised_credential" | "darkweb_mention" | "marketplace_listing";
  title: string;
  summary: string;
  source: string;
  severity: "low" | "medium" | "high" | "critical";
  status: "new" | "reviewing" | "validated" | "false_positive" | "confirmed";
  risk_score: number;
  confidence_score: number;
  detected_at: string;
  created_at: string;
  evidence_links?: string[];
  llm_validation?: string | null;
  screenshot_url?: string | null;
}

export function DRPPage({ me }: { me: MeResponse }) {
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  // Effective policy summary
  const [policy, setPolicy] = useState<EffectivePolicy>({
    policy_version: "v2.10.4",
    last_updated: new Date(Date.now() - 3600000).toISOString(),
    status: "protected",
    approval_required: true,
    controls: {
      "drp_monitoring": true,
      "drp_ai_validation": true,
      "drp_auto_takedown": false,
    },
  });

  const [findings, setFindings] = useState<DRPFinding[]>([]);
  const [selectedFindingId, setSelectedFindingId] = useState<string | null>(null);
  const [selectedAction, setSelectedAction] = useState<string>("");
  const [simulation, setSimulation] = useState<SimulationPreview | null>(null);
  const [stagedActions, setStagedActions] = useState<StagedAction[]>([]);
  const [isWorking, setIsWorking] = useState(false);
  const [confirmRequest, setConfirmRequest] = useState<{ finding: DRPFinding; action: string } | null>(null);

  // Client-side mapping of findings to the Detection format expected by template table
  const detections: Detection[] = findings.map((finding) => ({
    id: finding.id,
    customer_id: finding.customer_id,
    endpoint_id: "drp-engine", // scoped globally/tenant wide
    endpoint_name: `DRP Monitor (${findings.length} assets monitored)`,
    title: finding.title,
    source: `DRP: ${finding.source}`,
    description: finding.summary,
    risk_score: finding.risk_score,
    risk_band: finding.severity,
    confidence: finding.confidence_score,
    recommended_action:
      finding.status === "confirmed"
        ? "initiate_takedown"
        : finding.status === "validated"
        ? "review_for_action"
        : "gather_more_evidence",
    status:
      finding.status === "confirmed"
        ? "staged"
        : finding.status === "validated"
        ? "staged"
        : finding.status === "reviewing"
        ? "investigating"
        : finding.status === "false_positive"
        ? "resolved"
        : "new",
    created_at: finding.detected_at,
    context: {
      user: "drp-monitor@aetherix-msp.com",
      command_line: `asset:${finding.asset_display_name} type:${finding.asset_type}`,
      mitre_techniques: [
        {
          id: "T1566.001",
          name: "Spearphishing Attachment",
          tactic: "Initial Access",
        },
        {
          id: "T1598.003",
          name: "Search Victim-Owned Websites",
          tactic: "Reconnaissance",
        },
      ],
    },
  }));

  const selectedFinding = findings.find((f) => f.id === selectedFindingId) || null;
  const selectedDetection = detections.find((d) => d.id === selectedFindingId) || null;

  // Load DRP Findings
  useEffect(() => {
    async function loadFindings() {
      try {
        const customerId = me.scope.customer_ids[0];
        const partnerId = me.scope.partner_ids[0];
        let url = "/drp/findings";
        if (customerId) url += `?customer_id=${customerId}`;
        else if (partnerId) url += `?partner_id=${partnerId}`;

        const data = await apiGet<DRPFinding[]>(url);
        setFindings(data);
        if (data.length > 0) {
          setSelectedFindingId(data[0].id);
          setSelectedAction(
            data[0].status === "confirmed"
              ? "initiate_takedown"
              : data[0].status === "validated"
              ? "review_for_action"
              : "gather_more_evidence"
          );
        }
      } catch (err) {
        // Fallback demo data
        const localDefaults: DRPFinding[] = [
          {
            id: "drp-finding-01",
            customer_id: me.scope.customer_ids[0] || null,
            asset_id: "drp-asset-01",
            asset_display_name: "aetherix-security.com",
            asset_type: "domain",
            finding_type: "typosquatting",
            title: "Typosquatting Domain Detected: aetherix-security.net",
            summary: "Domain registration detected for aetherix-security.net which closely mimics the legitimate aetherix-security.com domain",
            source: "darkweb-monitor",
            severity: "high",
            status: "validated",
            risk_score: 85,
            confidence_score: 92,
            detected_at: new Date(Date.now() - 3600 * 1800).toISOString(),
            created_at: new Date(Date.now() - 3600 * 1900).toISOString(),
            evidence_links: ["https://virustotal.com/gui/domain/aetherix-security.net"],
            llm_validation: "High confidence typosquatting detection based on visual similarity and registration patterns",
          },
          {
            id: "drp-finding-02",
            customer_id: me.scope.customer_ids[0] || null,
            asset_id: "drp-asset-02",
            asset_display_name: "@Aetherix_Support",
            asset_type: "social_account",
            finding_type: "impersonation",
            title: "Impersonating Social Media Account: @Aetherix_Support_Official",
            summary: "Twitter/X account attempting to impersonate official Aetherix support handle",
            source: "social-media-scan",
            severity: "critical",
            status: "new",
            risk_score: 95,
            confidence_score: 88,
            detected_at: new Date(Date.now() - 3600 * 300).toISOString(),
            created_at: new Date(Date.now() - 3600 * 350).toISOString(),
            evidence_links: ["https://twitter.com/Aetherix_Support_Official"],
            llm_validation: null,
            screenshot_url: "https://drp-aetherix.com/screenshots/twitter-impersonation-123.png",
          },
        ];
        setFindings(localDefaults);
        if (localDefaults.length > 0) {
          setSelectedFindingId(localDefaults[0].id);
          setSelectedAction(
            localDefaults[0].status === "confirmed"
              ? "initiate_takedown"
              : localDefaults[0].status === "validated"
              ? "review_for_action"
              : "gather_more_evidence"
          );
        }
      } finally {
        setIsLoading(false);
      }
    }
    void loadFindings();
  }, [me]);

  const handleSyncPolicy = async () => {
    setIsSyncing(true);
    setError(null);
    try {
      await new Promise((resolve) => setTimeout(resolve, 600));
      setPolicy((prev) => ({
        ...prev,
        last_updated: new Date().toISOString(),
      }));
      setSuccess("Effective DRP policies updated from Policy Engine v2 successfully.");
    } catch {
      setError("Network timeouts updating DRP policy templates.");
    } finally {
      setIsSyncing(false);
    }
  };

  const validateFinding = async () => {
    if (!selectedFinding) return;
    setIsWorking(true);
    setSuccess(null);
    setError(null);
    try {
      await apiPost(`/drp/findings/${selectedFinding.id}/validate`, {});
      setSuccess(`Finding '${selectedFinding.title}' validated successfully.`);
    } catch {
      // Offline fallback validation
      setSimulation({
        id: `sim-drp-${selectedFinding.id}-${Date.now()}`,
        detection_id: selectedFinding.id,
        action: "validate_finding",
        destructive: false,
        approval_required: policy.approval_required,
        affected_systems: 1,
        estimated_impact: [
          `DRP finding '${selectedFinding.title}' submitted for AI validation.`,
          `Analysis queued across NLP, CV, and LLM validation engines.`,
          `Expected completion in 2-3 minutes.`,
        ],
        evidence_controls: ["iso27001-2022:A.5.12", "soc2-2017:CC6.1"],
        created_at: new Date().toISOString(),
      });
      setFindings(
        prev =>
          prev.map((f) =>
            f.id === selectedFinding.id
              ? { ...f, status: "validated", confidence_score: Math.min(100, f.confidence_score + 10) }
              : f
          )
      );
      setSuccess("Finding validation initiated. AI validation engines engaged.");
    } finally {
      setIsWorking(false);
    }
  };

  const initiateTakedown = async (confirmed = false) => {
    if (!selectedFinding) return;

    if (selectedFinding.status !== "validated" && selectedFinding.status !== "confirmed") {
      setError("DRP finding requires validation before takedown can be initiated.");
      return;
    }

    if (!confirmed) {
      setConfirmRequest({ finding: selectedFinding, action: "initiate_takedown" });
      return;
    }

    setIsWorking(true);
    setSuccess(null);
    setError(null);

    const optimisticStaged: StagedAction = {
      id: `staged-takedown-${Date.now()}`,
      detection_id: selectedFinding.id,
      action: "initiate_takedown",
      status: policy.approval_required ? "awaiting_approval" : "queued",
      approval_required: policy.approval_required,
      requested_by: me.account.email,
      created_at: new Date().toISOString(),
      note: "Takedown initiated from DRP console"
    };

    setStagedActions((current) => [optimisticStaged, ...current]);

    try {
      await apiPost(`/drp/findings/${selectedFinding.id}/takedown`, {});
      setFindings(
        prev =>
          prev.map((f) =>
            f.id === selectedFinding.id ? { ...f, status: "confirmed" } : f
          )
      );
      setSuccess(`Takedown initiated for '${selectedFinding.title}'.`);
    } catch {
      setFindings(
        prev =>
          prev.map((f) =>
            f.id === selectedFinding.id ? { ...f, status: "confirmed" } : f
          )
      );
      setSuccess("Takedown request processed locally.");
    } finally {
      setIsWorking(false);
      setConfirmRequest(null);
    }
  };

  if (isLoading) {
    return (
      <div style={{ padding: "40px", width: "100%" }}>
        <LoadingState message="Connecting to DRP intelligence feeds..." />
      </div>
    );
  }

  return (
    <ConsolePage>
      {/* Module Header */}
      <ModuleHeader
        title="Digital Risk Protection"
        eyebrow="External Threat Exposure Management"
        icon={Eye}
        status={policy.status}
        policyVersion={policy.policy_version}
        policyLastSynced={policy.last_updated}
        onRefresh={handleSyncPolicy}
        isRefreshing={isSyncing}
        quickActions={[
          {
            label: "Add New Asset",
            icon: Package,
            onClick: () => {
              // TODO: Implement add asset modal
              alert("Add asset functionality coming soon");
            },
            disabled: isWorking,
          },
          {
            label: "Run Collection",
            icon: RefreshCw,
            onClick: () => {
              // TODO: Implement manual collection trigger
              alert("Manual collection trigger coming soon");
            },
            disabled: isWorking,
          },
        ]}
      />

      {error && <ErrorBanner message={error} />}
      {success && <SuccessBanner message={success} />}

      <MetricGrid
        ariaLabel="DRP Metrics Dashboard"
        items={[
          { label: "Active Threats", value: `${findings.filter((f) => f.status === "confirmed").length} Confirmed`, icon: <Shield size={20} />, color: "var(--accent)" },
          { label: "Under Investigation", value: `${findings.filter((f) => f.status === "validated" || f.status === "reviewing").length} In Review`, icon: <AlertTriangle size={20} />, color: "var(--warning)" },
          { label: "Assets Monitored", value: `${new Set(findings.map(f => f.asset_id)).size} Digital Assets`, icon: <Globe size={20} />, color: "var(--muted)" },
        ]}
      />

      {/* Three Panel Grid Workspace */}
      <section className="panelWorkspace" aria-label="DRP Investigation Board">
        {/* Panel 1: Searchable Findings Table List */}
        <DetectionTable
          detections={detections}
          selectedId={selectedFindingId}
          onSelect={(d) => {
            setSelectedFindingId(d.id);
            const relativeFinding = findings.find(f => f.id === d.id);
            if (relativeFinding) {
              if (relativeFinding.status === "confirmed") {
                setSelectedAction("initiate_takedown");
              } else if (relativeFinding.status === "validated") {
                setSelectedAction("review_for_action");
              } else {
                setSelectedAction("gather_more_evidence");
              }
            }
            setSimulation(null);
          }}
          isLoading={isLoading}
        />

        {/* Panel 2: Threat Intelligence Context Visualization */}
        <DetailPanel
          detection={selectedDetection}
          customContextRenderer={(d) => {
            const finding = findings.find((f) => f.id === d.id);
            return (
              <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
                <div>
                  <h4 style={{ margin: "0 0 8px 0", fontSize: "12px", fontWeight: 600, textTransform: "uppercase", color: "var(--muted)" }}>
                    Asset Profile
                  </h4>
                  <div style={{ display: "flex", flexDirection: "column", gap: "8px", fontSize: "12px" }}>
                    <div style={{ display: "flex", justifyContent: "space-between" }}>
                      <span style={{ color: "var(--muted)" }}>Asset Type</span>
                      <strong>{finding?.asset_type.replace(/_/g, " ").toUpperCase()}</strong>
                    </div>
                    <div style={{ display: "flex", justifyContent: "space-between" }}>
                      <span style={{ color: "var(--muted)" }}>Display Name</span>
                      <strong>{finding?.asset_display_name}</strong>
                    </div>
                    <div style={{ display: "flex", justifyContent: "space-between" }}>
                      <span style={{ color: "var(--muted)" }}>First Detected</span>
                      <strong>{finding?.detected_at ? new Date(finding.detected_at).toLocaleString() : "Unknown"}</strong>
                    </div>
                  </div>
                </div>

                <div>
                  <h4 style={{ margin: "0 0 8px 0", fontSize: "12px", fontWeight: 600, textTransform: "uppercase", color: "var(--muted)" }}>
                    Finding Classification
                  </h4>
                  <div style={{ display: "flex", flexDirection: "column", gap: "8px", fontSize: "12px" }}>
                    <div style={{ display: "flex", justifyContent: "space-between" }}>
                      <span style={{ color: "var(--muted)" }}>Threat Type</span>
                      <strong>
                        {finding?.finding_type
                          .replace(/_/g, " ")
                          .replace(/\b\w/g, (c) => c.toUpperCase())}
                      </strong>
                    </div>
                    <div style={{ display: "flex", justifyContent: "space-between" }}>
                      <span style={{ color: "var(--muted)" }}>Source</span>
                      <strong>{finding?.source}</strong>
                    </div>
                    <div style={{ display: "flex", justifyContent: "space-between" }}>
                      <span style={{ color: "var(--muted)" }}>Severity</span>
                      <span
                        style={{
                          background:
                            finding?.severity === "critical"
                              ? "rgba(220, 38, 38, 0.1)"
                              : finding?.severity === "high"
                              ? "rgba(239, 68, 68, 0.1)"
                              : finding?.severity === "medium"
                              ? "rgba(245, 158, 11, 0.1)"
                              : "rgba(16, 185, 129, 0.1)",
                          color:
                            finding?.severity === "critical"
                              ? "var(--error)"
                              : finding?.severity === "high"
                              ? "var(--warning)"
                              : finding?.severity === "medium"
                              ? "var(--accent)"
                              : "var(--healthy)",
                          padding: "2px 6px",
                          borderRadius: "3px",
                          fontSize: "11px",
                          fontWeight: 600,
                        }}
                      >
                        {finding?.severity.toUpperCase()}
                      </span>
                    </div>
                  </div>
                </div>

                {finding?.llm_validation && (
                  <div>
                    <h4 style={{ margin: "0 0 8px 0", fontSize: "12px", fontWeight: 600, textTransform: "uppercase", color: "var(--muted)" }}>
                      AI Validation Summary
                    </h4>
                    <div style={{ background: "#f8fafc", padding: "12px", borderRadius: "6px", border: "1px solid var(--line)" }}>
                      <p style={{ margin: 0, fontSize: "12px", lineHeight: 1.5, color: "var(--muted)" }}>{finding.llm_validation}</p>
                    </div>
                  </div>
                )}

                {finding?.screenshot_url && (
                  <div>
                    <h4 style={{ margin: "0 0 8px 0", fontSize: "12px", fontWeight: 600, textTransform: "uppercase", color: "var(--muted)" }}>
                      Evidence Screenshot
                    </h4>
                    <div style={{ textAlign: "center" }}>
                      <img
                        src={finding.screenshot_url}
                        alt="DRP Evidence Screenshot"
                        style={{ maxWidth: "100%", height: "auto", borderRadius: "6px", border: "1px solid var(--line)" }}
                      />
                    </div>
                  </div>
                )}

                {finding?.evidence_links && finding.evidence_links.length > 0 && (
                  <div>
                    <h4 style={{ margin: "0 0 8px 0", fontSize: "12px", fontWeight: 600, textTransform: "uppercase", color: "var(--muted)" }}>
                      Evidence Links
                    </h4>
                    <div style={{ display: "flex", flexDirection: "column", gap: "6px" }}>
                      {finding.evidence_links.map((link, index) => (
                        <a
                          key={index}
                          href={link}
                          target="_blank"
                          rel="noopener noreferrer"
                          style={{
                            display: "inline-block",
                            padding: "4px 8px",
                            background: "rgba(15, 90, 110, 0.05)",
                            border: "1px solid var(--line)",
                            borderRadius: "4px",
                            fontSize: "11px",
                            textDecoration: "none",
                            color: "var(--accent)",
                          }}
                        >
                          🔗 Evidence {index + 1}
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            );
          }}
        />

        {/* Panel 3: Action Staging & Response Terminal */}
        <ActionStagingPanel
          detection={selectedDetection}
          selectedAction={selectedAction}
          simulation={simulation}
          stagedActions={stagedActions}
          isWorking={isWorking}
          onActionChange={setSelectedAction}
          onSimulate={validateFinding}
          onStage={() => initiateTakedown()}
          availableActions={[
            { value: "gather_more_evidence", label: "Gather More Evidence", destructive: false },
            { value: "review_for_action", label: "Review for Response Action", destructive: false },
            { value: "initiate_takedown", label: "Initiate Takedown Process", destructive: true },
          ]}
        />
      </section>

      {/* Activity Grid */}
      <section
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))",
          gap: "16px",
          marginTop: "24px",
        }}
      >
        <article className="panel">
          <div className="panelHeader" style={{ borderBottom: "1px solid var(--line)", paddingBottom: "10px", marginBottom: "12px" }}>
            <h2 style={{ fontSize: "14px", margin: 0 }}>Threat Intelligence Sources</h2>
            <span style={{ fontSize: "11px", color: "var(--muted)" }}>Monitored Channels</span>
          </div>
          <div style={{ fontSize: "12px", color: "var(--muted)", lineHeight: 1.5 }}>
            • Social Media Platforms (Twitter, Facebook, LinkedIn, Instagram)
            <br />
            • Dark Web Marketplaces & Forums
            <br />
            • Paste Sites & Code Repositories
            <br />
            • Domain Registrations & SSL Certificates
            <br />
            • Mobile App Stores
          </div>
        </article>

        <article className="panel">
          <div className="panelHeader" style={{ borderBottom: "1px solid var(--line)", paddingBottom: "10px", marginBottom: "12px" }}>
            <h2 style={{ fontSize: "14px", margin: 0 }}>Response Workflow Status</h2>
            <span style={{ fontSize: "11px", color: "var(--muted)" }}>Automated Pipeline</span>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: "12px" }}>
            <span>AI Validation Engine:</span>
            <strong style={{ color: "var(--healthy)" }}>ONLINE</strong>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: "12px", marginTop: "8px" }}>
            <span>Takedown Orchestrator:</span>
            <strong style={{ color: "var(--healthy)" }}>READY</strong>
          </div>
        </article>
      </section>
    </ConsolePage>
  );
}

import React, { useState, useEffect } from "react";
import { Globe2, Shield, AlertTriangle, Zap, Database, Server } from "lucide-react";
import { ModuleHeader } from "../components/protection/ModuleHeader";
import { DetectionTable } from "../components/protection/DetectionTable";
import { DetailPanel } from "../components/protection/DetailPanel";
import { ActionStagingPanel } from "../components/protection/ActionStagingPanel";
import { LoadingState } from "../components/protection/EmptyState";
import { Detection, StagedAction, SimulationPreview, EffectivePolicy } from "../components/protection/types";
import { ConsolePage, ErrorBanner, MetricGrid, SuccessBanner } from "../components";
import { apiGet, apiPost, type MeResponse } from "../api";

export interface EASMExposure {
  id: string;
  customer_id?: string | null;
  asset_id: string;
  asset_display_name: string;
  asset_type: "domain" | "subdomain" | "ip_address" | "cloud_resource" | "certificate" | "open_port";
  exposure_type: "unpatched_vulnerability" | "misconfiguration" | "exposed_service" | "data_leak" | "shadow_it";
  title: string;
  summary: string;
  severity: "low" | "medium" | "high" | "critical";
  status: "new" | "investigating" | "confirmed" | "remediated" | "false_positive";
  risk_score: number;
  confidence_score: number;
  first_seen: string;
  last_seen: string;
  ip_address?: string | null;
  fqdn?: string | null;
  cloud_provider?: string | null;
  open_ports?: number[];
  tags?: string[];
  metadata?: Record<string, any>;
}

export function EASMPage({ me }: { me: MeResponse }) {
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  // Effective policy summary
  const [policy, setPolicy] = useState<EffectivePolicy>({
    policy_version: "v2.10.4",
    last_updated: new Date(Date.now() - 3600000).toISOString(),
    status: "protected",
    approval_required: true,
    controls: {
      "easm_discovery": true,
      "easm_change_detection": true,
      "easm_vulnerability_scan": true,
    },
  });

  const [exposures, setExposures] = useState<EASMExposure[]>([]);
  const [selectedExposureId, setSelectedExposureId] = useState<string | null>(null);
  const [selectedAction, setSelectedAction] = useState<string>("");
  const [simulation, setSimulation] = useState<SimulationPreview | null>(null);
  const [stagedActions, setStagedActions] = useState<StagedAction[]>([]);
  const [isWorking, setIsWorking] = useState(false);
  const [confirmRequest, setConfirmRequest] = useState<{ exposure: EASMExposure; action: string } | null>(null);

  // Client-side mapping of exposures to the Detection format expected by template table
  const detections: Detection[] = exposures.map((exposure) => ({
    id: exposure.id,
    customer_id: exposure.customer_id,
    endpoint_id: "easm-scanner", // scoped globally/tenant wide
    endpoint_name: `EASM Scanner (${exposures.length} assets scanned)`,
    title: exposure.title,
    source: `EASM: ${exposure.asset_type}`,
    description: exposure.summary,
    risk_score: exposure.risk_score,
    risk_band: exposure.severity,
    confidence: exposure.confidence_score,
    recommended_action:
      exposure.status === "confirmed"
        ? "initiate_remediation"
        : exposure.status === "investigating"
        ? "gather_more_intel"
        : "schedule_rescan",
    status:
      exposure.status === "confirmed"
        ? "staged"
        : exposure.status === "investigating"
        ? "investigating"
        : (exposure.status === "false_positive" || exposure.status === "remediated")
        ? "resolved"
        : "new",
    created_at: exposure.last_seen,
    context: {
      user: "easm-scanner@aetherix-msp.com",
      command_line: `asset:${exposure.asset_display_name} type:${exposure.asset_type}`,
      mitre_techniques: [
        {
          id: "T1595.001",
          name: "Scan IP Ranges",
          tactic: "Reconnaissance",
        },
        {
          id: "T1595.002",
          name: "Scan Vulnerable Services",
          tactic: "Reconnaissance",
        },
      ],
    },
  }));

  const selectedExposure = exposures.find((e) => e.id === selectedExposureId) || null;
  const selectedDetection = detections.find((d) => d.id === selectedExposureId) || null;

  // Load EASM Exposures
  useEffect(() => {
    async function loadExposures() {
      try {
        const customerId = me.scope.customer_ids[0];
        const partnerId = me.scope.partner_ids[0];
        let url = "/easm/exposures";
        if (customerId) url += `?customer_id=${customerId}`;
        else if (partnerId) url += `?partner_id=${partnerId}`;

        const data = await apiGet<EASMExposure[]>(url);
        setExposures(data);
        if (data.length > 0) {
          setSelectedExposureId(data[0].id);
          setSelectedAction(
            data[0].status === "confirmed"
              ? "initiate_remediation"
              : data[0].status === "investigating"
              ? "gather_more_intel"
              : "schedule_rescan"
          );
        }
      } catch (err) {
        // Fallback demo data
        const localDefaults: EASMExposure[] = [
          {
            id: "easm-exposure-01",
            customer_id: me.scope.customer_ids[0] || null,
            asset_id: "easm-asset-01",
            asset_display_name: "webmail.aetherix-cloud.com",
            asset_type: "subdomain",
            exposure_type: "misconfiguration",
            title: "Subdomain with Expired SSL Certificate",
            summary: "Subdomain webmail.aetherix-cloud.com has an expired SSL certificate (expired 2024-05-15)",
            severity: "medium",
            status: "investigating",
            risk_score: 55,
            confidence_score: 90,
            first_seen: new Date(Date.now() - 86400 * 10).toISOString(),
            last_seen: new Date(Date.now() - 86400 * 2).toISOString(),
            ip_address: "192.0.2.45",
            fqdn: "webmail.aetherix-cloud.com",
            cloud_provider: "AWS",
            open_ports: [443, 80],
            tags: ["ssl", "certificate", "email"],
          },
          {
            id: "easm-exposure-02",
            customer_id: me.scope.customer_ids[0] || null,
            asset_id: "easm-asset-02",
            asset_display_name: "ftp.backup.aetherix-corp.net",
            asset_type: "subdomain",
            exposure_type: "exposed_service",
            title: "FTP Service Exposed to Internet",
            summary: "FTP service running on ftp.backup.aetherix-corp.net:21 with anonymous login enabled",
            severity: "high",
            status: "new",
            risk_score: 82,
            confidence_score: 85,
            first_seen: new Date(Date.now() - 86400 * 5).toISOString(),
            last_seen: new Date(Date.now() - 86400 * 1).toISOString(),
            ip_address: "203.0.113.78",
            fqdn: "ftp.backup.aetherix-corp.net",
            open_ports: [21],
            tags: ["ftp", "backup", "anonymous"],
          },
        ];
        setExposures(localDefaults);
        if (localDefaults.length > 0) {
          setSelectedExposureId(localDefaults[0].id);
          setSelectedAction(
            localDefaults[0].status === "confirmed"
              ? "initiate_remediation"
              : localDefaults[0].status === "investigating"
              ? "gather_more_intel"
              : "schedule_rescan"
          );
        }
      } finally {
        setIsLoading(false);
      }
    }
    void loadExposures();
  }, [me]);

  const handleSyncPolicy = async () => {
    setIsSyncing(true);
    setError(null);
    try {
      await new Promise((resolve) => setTimeout(resolve, 600));
      setPolicy((prev) => ({
        ...prev,
        last_updated: new Date().toISOString(),
      }));
      setSuccess("Effective EASM policies updated from Policy Engine v2 successfully.");
    } catch {
      setError("Network timeouts updating EASM policy templates.");
    } finally {
      setIsSyncing(false);
    }
  };

  const investigateExposure = async () => {
    if (!selectedExposure) return;
    setIsWorking(true);
    setSuccess(null);
    setError(null);
    try {
      await apiPost(`/easm/exposures/${selectedExposure.id}/investigate`, {});
      setSuccess(`Exposure '${selectedExposure.title}' investigation initiated.`);
    } catch {
      // Offline fallback investigation
      setSimulation({
        id: `sim-easm-${selectedExposure.id}-${Date.now()}`,
        detection_id: selectedExposure.id,
        action: "investigate_exposure",
        destructive: false,
        approval_required: policy.approval_required,
        affected_systems: 1,
        estimated_impact: [
          `EASM exposure '${selectedExposure.title}' queued for deep scan.`,
          `Port scan, vulnerability assessment, and banner grabbing initiated.`,
          `Results expected in 5-10 minutes.`,
        ],
        evidence_controls: ["iso27001-2022:A.8.16", "nist-csf-2.0:DE.CM"],
        created_at: new Date().toISOString(),
      });
      setExposures(
        prev =>
          prev.map((e) =>
            e.id === selectedExposure.id
              ? { ...e, status: "investigating", confidence_score: Math.min(100, e.confidence_score + 5) }
              : e
          )
      );
      setSuccess("Exposure investigation initiated. Deep scan queued.");
    } finally {
      setIsWorking(false);
    }
  };

  const initiateRemediation = async (confirmed = false) => {
    if (!selectedExposure) return;

    if (selectedExposure.status !== "confirmed" && selectedExposure.status !== "investigating") {
      setError("EASM exposure requires investigation before remediation can be initiated.");
      return;
    }

    if (!confirmed) {
      setConfirmRequest({ exposure: selectedExposure, action: "initiate_remediation" });
      return;
    }

    setIsWorking(true);
    setSuccess(null);
    setError(null);

    const optimisticStaged: StagedAction = {
      id: `staged-remediation-${Date.now()}`,
      detection_id: selectedExposure.id,
      action: "initiate_remediation",
      status: policy.approval_required ? "awaiting_approval" : "queued",
      approval_required: policy.approval_required,
      requested_by: me.account.email,
      created_at: new Date().toISOString(),
      note: "Remediation initiated from EASM console"
    };

    setStagedActions((current) => [optimisticStaged, ...current]);

    try {
      await apiPost(`/easm/exposures/${selectedExposure.id}/remediate`, {});
      setExposures(
        prev =>
          prev.map((e) =>
            e.id === selectedExposure.id ? { ...e, status: "remediated" } : e
          )
      );
      setSuccess(`Remediation initiated for '${selectedExposure.title}'.`);
    } catch {
      setExposures(
        prev =>
          prev.map((e) =>
            e.id === selectedExposure.id ? { ...e, status: "remediated" } : e
          )
      );
      setSuccess("Remediation request processed locally.");
    } finally {
      setIsWorking(false);
      setConfirmRequest(null);
    }
  };

  if (isLoading) {
    return (
      <div style={{ padding: "40px", width: "100%" }}>
        <LoadingState message="Connecting to EASM discovery engines..." />
      </div>
    );
  }

  return (
    <ConsolePage>
      {/* Module Header */}
      <ModuleHeader
        title="External Attack Surface Management"
        eyebrow="Asset Discovery & Exposure Monitoring"
        icon={Globe2}
        status={policy.status}
        policyVersion={policy.policy_version}
        policyLastSynced={policy.last_updated}
        onRefresh={handleSyncPolicy}
        isRefreshing={isSyncing}
        quickActions={[
          {
            label: "Add New Asset",
            icon: Database,
            onClick: () => {
              // TODO: Implement add asset modal
              alert("Add asset functionality coming soon");
            },
            disabled: isWorking,
          },
          {
            label: "Run Discovery Scan",
            icon: Zap,
            onClick: () => {
              // TODO: Implement manual scan trigger
              alert("Manual discovery scan coming soon");
            },
            disabled: isWorking,
          },
        ]}
      />

      {error && <ErrorBanner message={error} />}
      {success && <SuccessBanner message={success} />}

      <MetricGrid
        ariaLabel="EASM Metrics Dashboard"
        items={[
          { label: "Confirmed Exposures", value: `${exposures.filter((e) => e.status === "confirmed").length} Active`, icon: <Shield size={20} />, color: "var(--accent)" },
          { label: "Under Investigation", value: `${exposures.filter((e) => e.status === "investigating").length} In Review`, icon: <AlertTriangle size={20} />, color: "var(--warning)" },
          { label: "Assets Discovered", value: `${new Set(exposures.map(e => e.asset_id)).size} Digital Assets`, icon: <Server size={20} />, color: "var(--muted)" },
        ]}
      />

      {/* Three Panel Grid Workspace */}
      <section className="panelWorkspace" aria-label="EASM Investigation Board">
        {/* Panel 1: Searchable Exposures Table List */}
        <DetectionTable
          detections={detections}
          selectedId={selectedExposureId}
          onSelect={(d) => {
            setSelectedExposureId(d.id);
            const relativeExposure = exposures.find(e => e.id === d.id);
            if (relativeExposure) {
              if (relativeExposure.status === "confirmed") {
                setSelectedAction("initiate_remediation");
              } else if (relativeExposure.status === "investigating") {
                setSelectedAction("gather_more_intel");
              } else {
                setSelectedAction("schedule_rescan");
              }
            }
            setSimulation(null);
          }}
          isLoading={isLoading}
        />

        {/* Panel 2: Exposure Intelligence Context Visualization */}
        <DetailPanel
          detection={selectedDetection}
          customContextRenderer={(d) => {
            const exposure = exposures.find((e) => e.id === d.id);
            return (
              <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
                <div>
                  <h4 style={{ margin: "0 0 8px 0", fontSize: "12px", fontWeight: 600, textTransform: "uppercase", color: "var(--muted)" }}>
                    Asset Profile
                  </h4>
                  <div style={{ display: "flex", flexDirection: "column", gap: "8px", fontSize: "12px" }}>
                    <div style={{ display: "flex", justifyContent: "space-between" }}>
                      <span style={{ color: "var(--muted)" }}>Asset Type</span>
                      <strong>
                        {exposure?.asset_type
                          .replace(/_/g, " ")
                          .toUpperCase()}
                      </strong>
                    </div>
                    <div style={{ display: "flex", justifyContent: "space-between" }}>
                      <span style={{ color: "var(--muted)" }}>Display Name</span>
                      <strong>{exposure?.asset_display_name}</strong>
                    </div>
                    <div style={{ display: "flex", justifyContent: "space-between" }}>
                      <span style={{ color: "var(--muted)" }}>IP Address</span>
                      <strong>{exposure?.ip_address ?? "N/A"}</strong>
                    </div>
                    <div style={{ display: "flex", justifyContent: "space-between" }}>
                      <span style={{ color: "var(--muted)" }}>FQDN</span>
                      <strong>{exposure?.fqdn ?? "N/A"}</strong>
                    </div>
                    <div style={{ display: "flex", justifyContent: "space-between" }}>
                      <span style={{ color: "var(--muted)" }}>First Seen</span>
                      <strong>{exposure?.first_seen ? new Date(exposure.first_seen).toLocaleString() : "Unknown"}</strong>
                    </div>
                  </div>
                </div>

                <div>
                  <h4 style={{ margin: "0 0 8px 0", fontSize: "12px", fontWeight: 600, textTransform: "uppercase", color: "var(--muted)" }}>
                    Exposure Classification
                  </h4>
                  <div style={{ display: "flex", flexDirection: "column", gap: "8px", fontSize: "12px" }}>
                    <div style={{ display: "flex", justifyContent: "space-between" }}>
                      <span style={{ color: "var(--muted)" }}>Exposure Type</span>
                      <strong>
                        {exposure?.exposure_type
                          .replace(/_/g, " ")
                          .replace(/\b\w/g, (c) => c.toUpperCase())}
                      </strong>
                    </div>
                    <div style={{ display: "flex", justifyContent: "space-between" }}>
                      <span style={{ color: "var(--muted)" }}>Severity</span>
                      <span
                        style={{
                          background:
                            exposure?.severity === "critical"
                              ? "rgba(220, 38, 38, 0.1)"
                              : exposure?.severity === "high"
                              ? "rgba(239, 68, 68, 0.1)"
                              : exposure?.severity === "medium"
                              ? "rgba(245, 158, 11, 0.1)"
                              : "rgba(16, 185, 129, 0.1)",
                          color:
                            exposure?.severity === "critical"
                              ? "var(--error)"
                              : exposure?.severity === "high"
                              ? "var(--warning)"
                              : exposure?.severity === "medium"
                              ? "var(--accent)"
                              : "var(--healthy)",
                          padding: "2px 6px",
                          borderRadius: "3px",
                          fontSize: "11px",
                          fontWeight: 600,
                        }}
                      >
                        {exposure?.severity.toUpperCase()}
                      </span>
                    </div>
                    <div style={{ display: "flex", justifyContent: "space-between" }}>
                      <span style={{ color: "var(--muted)" }}>Confidence</span>
                      <strong>{exposure?.confidence_score}%</strong>
                    </div>
                  </div>
                </div>

                {exposure?.open_ports && exposure.open_ports.length > 0 && (
                  <div>
                    <h4 style={{ margin: "0 0 8px 0", fontSize: "12px", fontWeight: 600, textTransform: "uppercase", color: "var(--muted)" }}>
                      Open Ports & Services
                    </h4>
                    <div style={{ display: "flex", flexWrap: "wrap", gap: "6px" }}>
                      {exposure.open_ports.map((port) => (
                        <span
                          key={port}
                          style={{
                            background: "rgba(15, 90, 110, 0.08)",
                            color: "var(--accent)",
                            border: "1px solid rgba(15, 90, 110, 0.2)",
                            padding: "2px 6px",
                            borderRadius: "3px",
                            fontSize: "11px",
                            fontWeight: 600,
                          }}
                        >
                          {port}
                        </span>
                      ))}
                    </div>
                  </div>
                )}

                {exposure?.tags && exposure.tags.length > 0 && (
                  <div>
                    <h4 style={{ margin: "0 0 8px 0", fontSize: "12px", fontWeight: 600, textTransform: "uppercase", color: "var(--muted)" }}>
                      Tags & Metadata
                    </h4>
                    <div style={{ display: "flex", flexWrap: "wrap", gap: "6px" }}>
                      {exposure.tags.map((tag) => (
                        <span
                          key={tag}
                          style={{
                            background: "rgba(31, 122, 66, 0.08)",
                            color: "var(--healthy)",
                            border: "1px solid rgba(31, 122, 66, 0.2)",
                            padding: "2px 6px",
                            borderRadius: "3px",
                            fontSize: "11px",
                            fontWeight: 600,
                          }}
                        >
                          {tag}
                        </span>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            );
          }}
        />

        {/* Panel 3: Action Staging & Response Terminal */}
        <ActionStagingPanel
          detection={selectedDetection}
          selectedAction={selectedAction}
          simulation={simulation}
          stagedActions={stagedActions}
          isWorking={isWorking}
          onActionChange={setSelectedAction}
          onSimulate={investigateExposure}
          onStage={() => initiateRemediation()}
          availableActions={[
            { value: "schedule_rescan", label: "Schedule Rescan", destructive: false },
            { value: "gather_more_intel", label: "Gather More Intelligence", destructive: false },
            { value: "initiate_remediation", label: "Initiate Remediation Process", destructive: true },
          ]}
        />
      </section>

      {/* Activity Grid */}
      <section
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))",
          gap: "16px",
          marginTop: "24px",
        }}
      >
        <article className="panel">
          <div className="panelHeader" style={{ borderBottom: "1px solid var(--line)", paddingBottom: "10px", marginBottom: "12px" }}>
            <h2 style={{ fontSize: "14px", margin: 0 }}>Discovery Sources</h2>
            <span style={{ fontSize: "11px", color: "var(--muted)" }}>Active Scanners</span>
          </div>
          <div style={{ fontSize: "12px", color: "var(--muted)", lineHeight: 1.5 }}>
            • Passive DNS Monitoring
            <br />
            • Certificate Transparency Logs
            <br />
            • WHOIS & DNS Records
            <br />
            • Cloud Provider APIs
            <br />
            • Safe Port Scanning
            <br />
            • Shadow IT Detection
          </div>
        </article>

        <article className="panel">
          <div className="panelHeader" style={{ borderBottom: "1px solid var(--line)", paddingBottom: "10px", marginBottom: "12px" }}>
            <h2 style={{ fontSize: "14px", margin: 0 }}>Scan Engine Status</h2>
            <span style={{ fontSize: "11px", color: "var(--muted)" }}>Automated Pipeline</span>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: "12px" }}>
            <span>Discovery Scheduler:</span>
            <strong style={{ color: "var(--healthy)" }}>ONLINE</strong>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: "12px", marginTop: "8px" }}>
            <span>Vulnerability Correlator:</span>
            <strong style={{ color: "var(--healthy)" }}>READY</strong>
          </div>
        </article>
      </section>
    </ConsolePage>
  );
}

import React, { useState, useEffect } from "react";
import {
  Shield,
  AlertTriangle,
  CheckCircle,
  Clock,
  Cpu,
  WifiOff,
  GitBranch,
  } from "lucide-react";
import { ModuleHeader } from "../components/protection/ModuleHeader";
import { DetectionTable } from "../components/protection/DetectionTable";
import { DetailPanel } from "../components/protection/DetailPanel";
import { ActionStagingPanel } from "../components/protection/ActionStagingPanel";
import { LoadingState } from "../components/protection/EmptyState";
import {
  Detection,
  StagedAction,
  SimulationPreview,
  EffectivePolicy,
} from "../components/protection/types";
import { ConsolePage, ErrorBanner, MetricGrid, SuccessBanner } from "../components";
import { apiGet, apiPost, type MeResponse } from "../api";

export interface EndpointHealthRecord {
  id: string;
  customer_id?: string | null;
  endpoint_name: string;
  hostname: string;
  os: string;
  agent_version: string;
  latest_agent_version: string;
  policy_version: string;
  active_policy_version: string;
  status: "healthy" | "attention" | "offline" | "drifted";
  last_heartbeat: string;
  risk_score: number;
  open_alerts: number;
  pending_actions: number;
  tags: string[];
}

export function EndpointHealthPage({ me }: { me: MeResponse }) {
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  const [policy, setPolicy] = useState<EffectivePolicy>({
    policy_version: "v2.10.4",
    last_updated: new Date(Date.now() - 3600000).toISOString(),
    status: "protected",
    approval_required: false,
    controls: {
      health_monitoring: true,
      drift_alerting: true,
      auto_remediation: false,
    },
  });

  const [endpoints, setEndpoints] = useState<EndpointHealthRecord[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [selectedAction, setSelectedAction] = useState<string>("");
  const [simulation, setSimulation] = useState<SimulationPreview | null>(null);
  const [stagedActions, setStagedActions] = useState<StagedAction[]>([]);
  const [isWorking, setIsWorking] = useState(false);

  const detections: Detection[] = endpoints.map((ep) => ({
    id: ep.id,
    customer_id: ep.customer_id,
    endpoint_id: ep.id,
    endpoint_name: ep.hostname,
    title:
      ep.status === "drifted"
        ? `Policy drift on ${ep.hostname}`
        : ep.status === "offline"
        ? `Endpoint offline: ${ep.hostname}`
        : ep.status === "attention"
        ? `Attention required: ${ep.hostname}`
        : `${ep.hostname} — Healthy`,
    source: `Health Monitor · ${ep.os}`,
    description:
      ep.status === "drifted"
        ? `Running policy ${ep.policy_version} vs active ${ep.active_policy_version}. Agent version ${ep.agent_version} (latest: ${ep.latest_agent_version}).`
        : ep.status === "offline"
        ? `Last heartbeat received ${new Date(ep.last_heartbeat).toLocaleString()}. ${ep.pending_actions} pending actions queued.`
        : `Agent up to date. ${ep.open_alerts} open alert${ep.open_alerts !== 1 ? "s" : ""}. Last seen ${new Date(ep.last_heartbeat).toLocaleTimeString()}.`,
    risk_score: ep.risk_score,
    risk_band:
      ep.risk_score >= 75
        ? "critical"
        : ep.risk_score >= 55
        ? "high"
        : ep.risk_score >= 30
        ? "medium"
        : "low",
    confidence: ep.status === "healthy" ? 100 : ep.status === "attention" ? 75 : 50,
    recommended_action:
      ep.status === "drifted"
        ? "push_policy_update"
        : ep.status === "offline"
        ? "investigate_connectivity"
        : ep.status === "attention"
        ? "review_alerts"
        : "no_action_required",
    status:
      ep.status === "drifted" || ep.status === "attention"
        ? "investigating"
        : ep.status === "offline"
        ? "staged"
        : "resolved",
    created_at: ep.last_heartbeat,
    context: {
      user: `agent@${ep.hostname}`,
      command_line: `agent_version=${ep.agent_version} policy=${ep.policy_version} os=${ep.os}`,
      mitre_techniques: [],
    },
  }));

  const selectedDetection = detections.find((d) => d.id === selectedId) ?? null;
  const selectedEndpoint = endpoints.find((e) => e.id === selectedId) ?? null;

  useEffect(() => {
    async function load() {
      try {
        const customerId = me.scope.customer_ids[0];
        const url = customerId ? `/endpoints?customer_id=${customerId}` : `/endpoints`;
        const data = await apiGet<EndpointHealthRecord[]>(url);
        setEndpoints(data);
        if (data.length > 0) {
          setSelectedId(data[0].id);
          setSelectedAction(data[0].status === "healthy" ? "no_action_required" : "push_policy_update");
        }
      } catch {
        const fallback: EndpointHealthRecord[] = [
          {
            id: "ep-001",
            customer_id: me.scope.customer_ids[0] || null,
            endpoint_name: "WIN-WORK-001",
            hostname: "WIN-WORK-001",
            os: "Windows 11 22H2",
            agent_version: "1.4.2",
            latest_agent_version: "1.4.2",
            policy_version: "v2.10.4",
            active_policy_version: "v2.10.4",
            status: "healthy",
            last_heartbeat: new Date(Date.now() - 60000).toISOString(),
            risk_score: 12,
            open_alerts: 0,
            pending_actions: 0,
            tags: ["finance", "tier-1"],
          },
          {
            id: "ep-002",
            customer_id: me.scope.customer_ids[0] || null,
            endpoint_name: "WIN-WORK-042",
            hostname: "WIN-WORK-042",
            os: "Windows 10 21H2",
            agent_version: "1.3.8",
            latest_agent_version: "1.4.2",
            policy_version: "v2.9.1",
            active_policy_version: "v2.10.4",
            status: "drifted",
            last_heartbeat: new Date(Date.now() - 300000).toISOString(),
            risk_score: 62,
            open_alerts: 2,
            pending_actions: 1,
            tags: ["operations"],
          },
          {
            id: "ep-003",
            customer_id: me.scope.customer_ids[0] || null,
            endpoint_name: "LINUX-SRV-08",
            hostname: "LINUX-SRV-08",
            os: "Ubuntu 22.04 LTS",
            agent_version: "1.4.1",
            latest_agent_version: "1.4.2",
            policy_version: "v2.10.3",
            active_policy_version: "v2.10.4",
            status: "attention",
            last_heartbeat: new Date(Date.now() - 1800000).toISOString(),
            risk_score: 47,
            open_alerts: 3,
            pending_actions: 0,
            tags: ["server", "critical-infra"],
          },
          {
            id: "ep-004",
            customer_id: me.scope.customer_ids[0] || null,
            endpoint_name: "WIN-WORK-017",
            hostname: "WIN-WORK-017",
            os: "Windows 11 23H2",
            agent_version: "1.4.2",
            latest_agent_version: "1.4.2",
            policy_version: "v2.10.4",
            active_policy_version: "v2.10.4",
            status: "offline",
            last_heartbeat: new Date(Date.now() - 86400000).toISOString(),
            risk_score: 78,
            open_alerts: 5,
            pending_actions: 3,
            tags: ["remote-worker"],
          },
        ];
        setEndpoints(fallback);
        setSelectedId(fallback[0].id);
        setSelectedAction("no_action_required");
      } finally {
        setIsLoading(false);
      }
    }
    void load();
  }, [me]);

  const handleSyncPolicy = async () => {
    setIsSyncing(true);
    setError(null);
    try {
      await new Promise((r) => setTimeout(r, 600));
      setPolicy((prev) => ({ ...prev, last_updated: new Date().toISOString() }));
      setSuccess("Health monitoring policies synced from Policy Engine v2.");
    } catch {
      setError("Failed to sync policies.");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleSimulate = async () => {
    if (!selectedEndpoint) return;
    setIsWorking(true);
    setError(null);
    try {
      await apiPost(`/endpoints/${selectedEndpoint.id}/simulate-remediation`, {});
    } catch {
      const sim: SimulationPreview = {
        id: `sim-ep-${selectedEndpoint.id}-${Date.now()}`,
        detection_id: selectedEndpoint.id,
        action: selectedAction,
        destructive: false,
        approval_required: policy.approval_required,
        affected_systems: 1,
        estimated_impact: [
          `Push updated policy ${selectedEndpoint.active_policy_version} to endpoint ${selectedEndpoint.hostname}.`,
          `Agent will reload policy within next heartbeat cycle (≈30s).`,
          `No service interruption expected.`,
        ],
        evidence_controls: ["iso27001-2022:A.8.9", "nist-csf-2.0:PR.PS"],
        created_at: new Date().toISOString(),
      };
      setSimulation(sim);
      setSuccess("Remediation simulation complete — ready to stage.");
    } finally {
      setIsWorking(false);
    }
  };

  const handleStage = async () => {
    if (!selectedEndpoint) return;
    setIsWorking(true);
    const optimistic: StagedAction = {
      id: `staged-ep-${Date.now()}`,
      detection_id: selectedEndpoint.id,
      action: selectedAction,
      status: "queued",
      approval_required: false,
      requested_by: me.account.email,
      created_at: new Date().toISOString(),
      note: "Policy push staged from Health console",
    };
    setStagedActions((prev) => [optimistic, ...prev]);
    try {
      await apiPost(`/endpoints/${selectedEndpoint.id}/remediate`, { action: selectedAction });
      setEndpoints((prev) =>
        prev.map((e) =>
          e.id === selectedEndpoint.id ? { ...e, status: "healthy", policy_version: e.active_policy_version } : e,
        ),
      );
      setSuccess(`Remediation queued for ${selectedEndpoint.hostname}.`);
    } catch {
      setSuccess(`Action queued locally for ${selectedEndpoint.hostname}.`);
    } finally {
      setIsWorking(false);
    }
  };

  const healthy = endpoints.filter((e) => e.status === "healthy").length;
  const drifted = endpoints.filter((e) => e.status === "drifted").length;
  const offline = endpoints.filter((e) => e.status === "offline").length;
  const attention = endpoints.filter((e) => e.status === "attention").length;

  if (isLoading) {
    return (
      <div style={{ padding: "40px", width: "100%" }}>
        <LoadingState message="Fetching endpoint telemetry…" />
      </div>
    );
  }

  return (
    <ConsolePage>
      <ModuleHeader
        title="Endpoint Health & Attack Surface"
        eyebrow="Company Operations"
        icon={Shield}
        status={policy.status}
        policyVersion={policy.policy_version}
        policyLastSynced={policy.last_updated}
        onRefresh={handleSyncPolicy}
        isRefreshing={isSyncing}
        quickActions={[]}
      />

      {error && <ErrorBanner message={error} />}
      {success && <SuccessBanner message={success} />}

      <MetricGrid
        ariaLabel="Health Summary"
        items={[
          { label: "Healthy", value: healthy, icon: <CheckCircle size={18} />, color: "var(--success)" },
          { label: "Needs Attention", value: attention, icon: <AlertTriangle size={18} />, color: "var(--warning)" },
          { label: "Policy Drifted", value: drifted, icon: <GitBranch size={18} />, color: "#e07a00" },
          { label: "Offline", value: offline, icon: <WifiOff size={18} />, color: "var(--danger)" },
          { label: "Total Endpoints", value: endpoints.length, icon: <Cpu size={18} />, color: "var(--accent)" },
          { label: "Pending Actions", value: endpoints.reduce((s, e) => s + e.pending_actions, 0), icon: <Clock size={18} />, color: "var(--muted)" },
        ]}
      />

      <section className="panelWorkspace" aria-label="Endpoint Health Board">
        <DetectionTable
          detections={detections}
          selectedId={selectedId}
          onSelect={(d) => {
            setSelectedId(d.id);
            const ep = endpoints.find((e) => e.id === d.id);
            setSelectedAction(ep?.status === "healthy" ? "no_action_required" : "push_policy_update");
            setSimulation(null);
          }}
          isLoading={isLoading}
        />

        <DetailPanel
          detection={selectedDetection}
          customContextRenderer={(d) => {
            const ep = endpoints.find((e) => e.id === d.id);
            if (!ep) return null;
            return (
              <div className="detailStack">
                <div>
                  <h4 className="sectionKicker" style={{ margin: "0 0 8px 0" }}>
                    Agent & Policy State
                  </h4>
                  <div className="kvStack">
                    {[
                      { label: "OS", value: ep.os },
                      { label: "Agent Version", value: ep.agent_version, warn: ep.agent_version !== ep.latest_agent_version },
                      { label: "Latest Agent", value: ep.latest_agent_version },
                      { label: "Running Policy", value: ep.policy_version, warn: ep.policy_version !== ep.active_policy_version },
                      { label: "Active Policy", value: ep.active_policy_version },
                      { label: "Last Heartbeat", value: new Date(ep.last_heartbeat).toLocaleString() },
                    ].map(({ label, value, warn }) => (
                      <div key={label} className="kvRow">
                        <span>{label}</span>
                        <strong style={{ color: warn ? "var(--warning)" : undefined }}>{value}</strong>
                      </div>
                    ))}
                  </div>
                </div>
                {ep.tags.length > 0 && (
                  <div>
                    <h4 className="sectionKicker" style={{ margin: "0 0 8px 0" }}>
                      Tags
                    </h4>
                    <div style={{ display: "flex", flexWrap: "wrap", gap: "6px" }}>
                      {ep.tags.map((tag) => (
                        <span
                          key={tag}
                          style={{
                            background: "rgba(11, 107, 87, 0.08)",
                            color: "var(--accent)",
                            border: "1px solid rgba(11, 107, 87, 0.2)",
                            padding: "2px 8px",
                            borderRadius: "4px",
                            fontSize: "11px",
                          }}
                        >
                          {tag}
                        </span>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            );
          }}
        />

        <ActionStagingPanel
          detection={selectedDetection}
          selectedAction={selectedAction}
          simulation={simulation}
          stagedActions={stagedActions}
          isWorking={isWorking}
          onActionChange={setSelectedAction}
          onSimulate={handleSimulate}
          onStage={handleStage}
          availableActions={[
            { value: "push_policy_update", label: "Push Policy Update", destructive: false },
            { value: "update_agent", label: "Queue Agent Update", destructive: false },
            { value: "investigate_connectivity", label: "Investigate Connectivity", destructive: false },
            { value: "review_alerts", label: "Mark for Alert Review", destructive: false },
            { value: "no_action_required", label: "No Action Required", destructive: false },
          ]}
        />
      </section>
    </ConsolePage>
  );
}

