                          if (field.type === "boolean") {
                            return (
                              <label key={field.key} className="toggleRow">
                                <input
                                  type="checkbox"
                                  checked={Boolean(value)}
                                  disabled={locked && field.key !== "enabled"}
                                  onChange={(event) => setModuleField(module.key, field.key, event.target.checked)}
                                />
                                {field.label}
                              </label>
