                          }
                          if (field.type === "select") {
                            return (
                              <label key={field.key}>
                                {field.label}
                                <select
                                  value={String(value ?? field.options?.[0] ?? "")}
                                  disabled={locked}
                                  onChange={(event) => setModuleField(module.key, field.key, event.target.value)}
