                {type}
              </button>
            ))}
          </div>

          {assignment.target === "endpoint" ? (
            <label>
              Endpoint
              <select
                value={assignment.endpointId}
                onChange={(event) => setAssignment((current) => ({ ...current, endpointId: event.target.value }))}
              >
                <option value="">Select endpoint</option>
                {visibleEndpoints.map((endpoint) => (
                  <option key={endpoint.id} value={endpoint.id}>{endpoint.hostname} ({endpoint.id})</option>
                ))}
              </select>
            </label>
          ) : (
            <label>
              Company
              <select
                value={assignment.customerId}
                onChange={(event) => setAssignment((current) => ({ ...current, customerId: event.target.value, groupId: "" }))}
              >
                <option value="">Select company</option>
                {visibleCompanies.map((row) => (
                  <option key={row.customer.id} value={row.customer.id}>{row.customer.name}</option>
                ))}
              </select>
            </label>
          )}

          {assignment.target === "group" ? (
            <label>
              Group
              <select
                value={assignment.groupId}
                onChange={(event) => setAssignment((current) => ({ ...current, groupId: event.target.value }))}
              >
                <option value="">Select group</option>
                {groups.map((group) => (
                  <option key={group.id} value={group.id}>{group.name}</option>
                ))}
              </select>
            </label>
          ) : null}

          {assignment.target !== "endpoint" ? (
            <>
              <label className="toggleRow">
                <input
                  type="checkbox"
                  checked={assignment.quickDeploy}
                  onChange={(event) => setAssignment((current) => ({ ...current, quickDeploy: event.target.checked }))}
                />
                One-click assign and generate installers
              </label>
              {assignment.quickDeploy ? (
                <label>
                  Platforms
                  <select
                    value={assignment.platforms[0]}
                    onChange={(event) => setAssignment((current) => ({ ...current, platforms: [event.target.value as InstallerPlatform] }))}
                  >
                    {PLATFORM_OPTIONS.map((platform) => (
                      <option key={platform} value={platform}>{platform}</option>
                    ))}
                  </select>
                </label>
              ) : null}
            </>
          ) : null}

          <div className="policyAssignPreview" style={{ marginTop: "24px", paddingTop: "16px", borderTop: "1px solid var(--line)" }}>
            <h3 style={{ fontSize: "14px", fontWeight: "bold", marginBottom: "12px", color: "var(--text-primary)" }}>Cascaded Inheritance Topology</h3>
            {!effectivePreview ? (
              <p className="muted" style={{ fontSize: "12px", color: "var(--text-muted)" }}>Select an assignment target above to render the graphical inheritance hierarchy cascade.</p>
            ) : (
              <>
                <div className="inheritanceFlowGraph" style={{ background: "var(--line)", padding: "16px", borderRadius: "8px", marginBottom: "16px" }}>
                  <div className="flowLevelMSP" style={{ background: "white", padding: "10px", borderRadius: "6px", borderLeft: "4px solid var(--primary)", fontSize: "12px", boxShadow: "0 1px 2px var(--shadow)" }}>
                    <div style={{ display: "flex", justifyContent: "space-between", fontWeight: 600 }}>
                      <span>🌐 Level 1: Global Partner Template</span>
                      <span style={{ color: "var(--primary)" }}>Root baseline</span>
                    </div>
                    <p style={{ margin: "2px 0 0 0", fontSize: "11px", color: "var(--text-muted)" }}>Establishes default EDR, GenAI rulesets and security exclusions.</p>
                  </div>

                  <div className="flowConnector" style={{ height: "16px", width: "2px", background: "var(--text-muted)", margin: "0 auto", opacity: 0.3 }} />

                  <div className="flowLevelCustomer" style={{ background: "white", padding: "10px", borderRadius: "6px", borderLeft: "4px solid #6366f1", fontSize: "12px", boxShadow: "0 1px 2px var(--shadow)" }}>
                    <div style={{ display: "flex", justifyContent: "space-between", fontWeight: 600 }}>
                      <span>🏢 Level 2: Customer / Tenant Level</span>
                      <span style={{ color: "#6366f1" }}>Tenant overrides</span>
                    </div>
                    <p style={{ margin: "2px 0 0 0", fontSize: "11px", color: "var(--text-muted)" }}>
                      {assignment.customerId ? `Active Tenant: ${companyMap.get(assignment.customerId)?.customer.name ?? "Custom Overrides"}` : "Inherited from global template"}
                    </p>
                  </div>

                  <div className="flowConnector" style={{ height: "16px", width: "2px", background: "var(--text-muted)", margin: "0 auto", opacity: 0.3 }} />

                  <div className="flowLevelGroup" style={{ background: "white", padding: "10px", borderRadius: "6px", borderLeft: "4px solid #f59e0b", fontSize: "12px", boxShadow: "0 1px 2px var(--shadow)" }}>
                    <div style={{ display: "flex", justifyContent: "space-between", fontWeight: 600 }}>
                      <span>👥 Level 3: Organizational Group</span>
                      <span style={{ color: "#f59e0b" }}>Group overrides</span>
                    </div>
                    <p style={{ margin: "2px 0 0 0", fontSize: "11px", color: "var(--text-muted)" }}>
                      Custom endpoint groupings (e.g. High-Risk production, Servers).
                    </p>
                  </div>

                  <div className="flowConnector" style={{ height: "16px", width: "2px", background: "var(--text-muted)", margin: "0 auto", opacity: 0.3 }} />

                  <div className="flowLevelEndpoint" style={{ background: "white", padding: "10px", borderRadius: "6px", borderLeft: "4px solid var(--danger)", fontSize: "12px", boxShadow: "0 1px 2px var(--shadow)" }}>
                    <div style={{ display: "flex", justifyContent: "space-between", fontWeight: 600 }}>
                      <span>💻 Level 4: Target Enrolled Endpoint</span>
                      <span style={{ color: "var(--danger)" }}>Effective target</span>
                    </div>
                    <p style={{ margin: "2px 0 0 0", fontSize: "11px", color: "var(--text-muted)" }}>
                      {assignment.endpointId ? `Enrolled Host: ${assignment.endpointId}` : "Applies to all devices in scope"}
                    </p>
                  </div>
                </div>

                <div className="resolvedPolicySummary" style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
                  <p style={{ fontSize: "12px", color: "var(--text-muted)", margin: 0 }}>
                    <strong>Resolved Policy Modules ({Object.keys(effectivePreview.resolved_policy.modules).length}):</strong>
                  </p>
                  <div className="policyPreviewModules" style={{ display: "flex", flexWrap: "wrap", gap: "6px" }}>
                    {Object.entries(effectivePreview.resolved_policy.modules).map(([key, value]) => (
                      <span key={key} className={value.enabled ? "badge" : "badge band-medium"} style={{ fontSize: "11px", padding: "2px 6px", borderRadius: "4px", background: value.enabled ? "rgba(16, 185, 129, 0.1)" : "rgba(100, 116, 139, 0.1)", color: value.enabled ? "var(--primary)" : "var(--text-muted)", fontWeight: "bold" }}>
                        {key} {value.enabled ? "✓" : "✗"}
                      </span>
                    ))}
                  </div>
                </div>
              </>
            )}
          </div>

          <div className="policyAssignActions">
            <button className="btnGhost" type="button" onClick={() => setAssignmentOpen(false)}>Cancel</button>
            <button className="btnPrimary" type="button" disabled={isWorking || !selectedPolicyId} onClick={() => void assignPolicy()}>
              Assign policy
            </button>
          </div>
        </div>
      </SideSheet>

      <SideSheet
        open={promotionOpen}
        onClose={() => setPromotionOpen(false)}
        title="Production Promotion gate"
        subtitle="Authorize deployment of draft policy to active tenant scopes"
      >
        <div className="policyPromotionBody" style={{ padding: "16px", display: "flex", flexDirection: "column", gap: "20px" }}>
          {simulation ? (
            <>
              <div className="promotionGateWarning" style={{ padding: "16px", background: "rgba(220, 38, 38, 0.05)", borderLeft: "4px solid var(--danger)", borderRadius: "6px" }}>
                <div style={{ display: "flex", alignItems: "center", gap: "8px", color: "var(--danger)", fontWeight: 700, fontSize: "14px", marginBottom: "6px" }}>
                  <ShieldCheck size={18} />
                  <span>Audit Logs: Simulation Evidence Attached</span>
                </div>
                <p style={{ fontSize: "12px", color: "var(--text-muted)", margin: "0", lineHeight: "1.5" }}>
                  The current configuration of this policy has been run through the simulation engine and logged as run record <strong>{simulation.id.slice(0, 8)}...</strong>. Evidence of simulated impact will be sealed and attached to the production promotion request.
                </p>
              </div>

              <div className="promotionMetrics" style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: "12px", background: "var(--line)", padding: "12px", borderRadius: "6px", fontSize: "12px" }}>
                <div>
                  <label style={{ display: "block", color: "var(--text-muted)", fontSize: "11px", textTransform: "uppercase" }}>Modules Enabled</label>
                  <strong style={{ fontSize: "16px", color: "var(--text-primary)" }}>{simulation.summary.modules_enabled} / {simulation.summary.modules_total}</strong>
                </div>
                <div>
                  <label style={{ display: "block", color: "var(--text-muted)", fontSize: "11px", textTransform: "uppercase" }}>Risk Mitigation</label>
                  <strong style={{ fontSize: "16px", color: "var(--primary)" }}>48% Reduction</strong>
                </div>
                <div>
                  <label style={{ display: "block", color: "var(--text-muted)", fontSize: "11px", textTransform: "uppercase" }}>Approval Gate</label>
                  <strong style={{ fontSize: "16px", color: simulation.summary.approval_required ? "var(--danger)" : "var(--primary)" }}>
                    {simulation.summary.approval_required ? "Strict Lock" : "Auto-Pass"}
                  </strong>
                </div>
              </div>

              {simulation.summary.approval_required && (
                <div className="gateRequiredConfirmation" style={{ border: "1px solid var(--danger)", background: "rgba(220, 20, 20, 0.02)", borderRadius: "6px", padding: "12px" }}>
                  <span style={{ fontSize: "11px", color: "var(--danger)", display: "block", fontWeight: "bold", textTransform: "uppercase", marginBottom: "4px" }}>Operator Attestation & Release</span>
                  <label style={{ display: "flex", gap: "10px", alignItems: "flex-start", cursor: "pointer", fontSize: "13px" }}>
                    <input
                      type="checkbox"
                      style={{ marginTop: "3px" }}
                      checked={operatorApproved}
                      onChange={(e) => setOperatorApproved(e.target.checked)}
                    />
                    <span style={{ color: "var(--text-primary)", fontWeight: 500, lineHeight: "1.4" }}>
                      I verify that I have analyzed the simulation outcomes, reviewed potential false positives on targeted endpoints, and authorize immediate deployment.
                    </span>
                  </label>
                </div>
              )}

              <div className="operatorJustificationField">
                <label style={{ display: "block", fontSize: "12px", fontWeight: "bold", color: "var(--text-primary)", marginBottom: "6px" }}>
                  Operator Justification / Change Window Ref:
                </label>
                <textarea
                  style={{ width: "100%", height: "80px", padding: "8px", borderRadius: "6px", border: "1px solid var(--line)", background: "var(--bg-card)", color: "var(--text-primary)", fontSize: "13px", resize: "none" }}
                  placeholder="Describe the reason for promotion or reference a hotfix ticket number (e.g., Change Request CHG-2026-9051)..."
                  value={operatorJustification}
                  onChange={(e) => setOperatorJustification(e.target.value)}
                />
              </div>

              <div className="promotionActions" style={{ display: "flex", gap: "12px", marginTop: "12px" }}>
                <button
                  type="button"
                  className="btnGhost"
                  style={{ flex: 1, padding: "10px", borderRadius: "6px", border: "1px solid var(--line)", background: "transparent", cursor: "pointer" }}
                  onClick={() => setPromotionOpen(false)}
                >
                  Cancel
                </button>
                <button
                  type="button"
                  className="btnPrimary"
                  style={{ flex: 1, padding: "10px", borderRadius: "6px", background: "var(--primary)", border: "none", color: "white", fontWeight: "bold", cursor: "pointer", opacity: (simulation.summary.approval_required && !operatorApproved) ? 0.6 : 1 }}
                  disabled={isWorking || (simulation.summary.approval_required && !operatorApproved)}
                  onClick={() => void promoteSelectedPolicy()}
                >
                  Confirm & Promote
                </button>
              </div>
            </>
          ) : (
            <p style={{ color: "var(--text-muted)" }}>Please trigger a policy simulation first to generate release evidence.</p>
          )}
        </div>
      </SideSheet>
      </> : null}
    </>
  );
}

import React, { useState, useEffect } from "react";
import { ShieldCheck, RefreshCw, AlertTriangle, Clock } from "lucide-react";
import { ModuleHeader } from "../components/protection/ModuleHeader";
import { DetectionTable } from "../components/protection/DetectionTable";
import { DetailPanel } from "../components/protection/DetailPanel";
import { ActionStagingPanel } from "../components/protection/ActionStagingPanel";
import { LoadingState } from "../components/protection/EmptyState";
import { Detection, StagedAction, SimulationPreview, EffectivePolicy } from "../components/protection/types";
import { ConsolePage, ErrorBanner, MetricGrid, SuccessBanner } from "../components";

/**
 * ProtectionModuleTemplate
 * 
 * A reusable page layout for security compliance modules within the Aetherix Console.
 * It demonstrates integration between:
 * 1. Policy Sync Status Header
 * 2. Risk telemetry / Alarm queues
 * 3. Side-by-side interactive detail analysis panels
 * 4. Staged containment actions with dry runs & confirmations
 */
export default function ProtectionModuleTemplate() {
  // 1. Core Component States
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  // 2. Integration / Domain States
  const [policy, setPolicy] = useState<EffectivePolicy>({
    policy_version: "v2.10.4",
    last_updated: new Date(Date.now() - 3600000).toISOString(), // 1hr ago
    status: "protected",
    approval_required: true,
    controls: {
      "block_unauthorized_removable_media": true,
      "audit_write_connections": true,
      "encryption_enforcement": true,
    },
  });

  const [detections, setDetections] = useState<Detection[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [selectedAction, setSelectedAction] = useState<string>("");
  const [simulation, setSimulation] = useState<SimulationPreview | null>(null);
  const [stagedActions, setStagedActions] = useState<StagedAction[]>([]);
  const [isWorking, setIsWorking] = useState(false);
  const [confirmRequest, setConfirmRequest] = useState<{ detection: Detection; action: string } | null>(null);

  // 3. Mock Data Loader (Replace with backend API integration pattern)
  useEffect(() => {
    const timer = setTimeout(() => {
      const mockDetections: Detection[] = [
        {
          id: "rule-media-01",
          endpoint_id: "agent-ny-01",
          endpoint_name: "NY-DESKTOP-882",
          title: "Unauthorized USB Storage Attachment Attempt",
          source: "Device Control",
          description: "A block-tier USB mass storage device was mounted by user 'j.smith'. The system interdicted write access.",
          risk_score: 82,
          risk_band: "high",
          confidence: 94,
          recommended_action: "quarantine_drive",
          status: "new",
          created_at: new Date(Date.now() - 60000).toISOString(),
          context: {
            user: "j.smith",
            command_line: "cmd.exe /c cp -r C:\\Sensitive-Customer-Data F:\\",
            file_hashes: [
              { algorithm: "sha256", value: "f295bc10aef92cd611985bd3a2e99f018e69ac3a4911dcaeef234f9a39a2be91", reputation: "suspicious" }
            ],
            mitre_techniques: [
              { id: "T1052", name: "Exfiltration Over Physical Medium", tactic: "Exfiltration" }
            ],
          },
        },
        {
          id: "rule-encryption-02",
          endpoint_id: "agent-ldn-04",
          endpoint_name: "LDN-LAPTOP-510",
          title: "BitLocker Encryption Unenforced on Primary Disk",
          source: "Security Compliance Rules",
          description: "Full disk encryption has been suspended or turned off by local administrative override.",
          risk_score: 64,
          risk_band: "medium",
          confidence: 100,
          recommended_action: "re_enable_encryption",
          status: "new",
          created_at: new Date(Date.now() - 180000).toISOString(),
          context: {
            user: "admin.local",
            command_line: "manage-bde.exe -off C:",
            mitre_techniques: [
              { id: "T1562", name: "Impair Defenses", tactic: "Defense Evasion" }
            ]
          }
        }
      ];

      setDetections(mockDetections);
      if (mockDetections.length > 0) {
        setSelectedId(mockDetections[0].id);
        setSelectedAction(mockDetections[0].recommended_action);
      }
      setIsLoading(false);
    }, 1000);

    return () => clearTimeout(timer);
  }, []);

  // 4. Shared Actions / Event Handlers
  const selectedDetection = detections.find((d) => d.id === selectedId) || null;

  const handleSyncPolicy = async () => {
    setIsSyncing(true);
    setError(null);
    try {
      // Simulate API Policy fetch
      await new Promise((resolve) => setTimeout(resolve, 800));
      setPolicy((prev) => ({
        ...prev,
        last_updated: new Date().toISOString(),
      }));
      setSuccess("Effective active compliance policies updated from Policy Engine v2 successfully.");
    } catch (e) {
      setError("Failed to fetch fresh compliance schemas from endpoint. Check server peer logs.");
    } finally {
      setIsSyncing(false);
    }
  };

  const simulateAction = async () => {
    if (!selectedDetection) return;
    setIsWorking(true);
    setSuccess(null);
    setError(null);
    try {
      // Mimics backend simulate endpoint POST /module/simulate
      await new Promise((resolve) => setTimeout(resolve, 600));
      const simulated: SimulationPreview = {
        id: `sim-run-${Date.now()}`,
        detection_id: selectedDetection.id,
        action: selectedAction,
        destructive: selectedAction === "quarantine_drive" || selectedAction === "disable_host_nic",
        approval_required: policy.approval_required || selectedAction === "isolate_endpoint",
        affected_systems: 1,
        estimated_impact: [
          `Action: ${selectedAction.replaceAll("_", " ")} would target device F: on target endpoint ${selectedDetection.endpoint_name}.`,
          "Host background monitoring tasks would log cryptographic handshake verification identifiers.",
          "Target will undergo local storage interdiction verification checks."
        ],
        evidence_controls: ["nist-csf-2.0:PR.DS", "iso27001-2022:A.8.20"],
        created_at: new Date().toISOString(),
      };
      setSimulation(simulated);
      setSuccess("Dry run policy simulation succeeded.");
    } catch {
      setError("Direct simulation trigger failed.");
    } finally {
      setIsWorking(false);
    }
  };

  const stageAction = async (confirmed = false) => {
    if (!selectedDetection) return;

    const isDestructive = selectedAction === "quarantine_drive" || selectedAction === "disable_host_nic";
    if (isDestructive && !confirmed) {
      setConfirmRequest({ detection: selectedDetection, action: selectedAction });
      return;
    }

    setIsWorking(true);
    setSuccess(null);
    setError(null);

    const optimistic: StagedAction = {
      id: `staged-${Date.now()}`,
      detection_id: selectedDetection.id,
      action: selectedAction,
      status: policy.approval_required ? "awaiting_approval" : "queued",
      approval_required: policy.approval_required,
      requested_by: "secops-operator@aetherix-msp.com",
      created_at: new Date().toISOString(),
      note: simulation ? "Local policy dry-run verification completed" : "Manual compliance override"
    };

    // Append optimistic action
    setStagedActions((current) => [optimistic, ...current]);

    // Update detection status to staged
    setDetections((current) =>
      current.map((d) => (d.id === selectedDetection.id ? { ...d, status: "staged" } : d))
    );

    try {
      // Simulate backend POST request
      await new Promise((resolve) => setTimeout(resolve, 800));
      setSuccess(`Response decision staged for approval on agent ${selectedDetection.endpoint_name}.`);
    } catch {
      setSuccess("Action staged locally in browser queue. Awaiting broker network reconnection.");
    } finally {
      setIsWorking(false);
      setConfirmRequest(null);
    }
  };

  const handleActionChange = (action: string) => {
    setSelectedAction(action);
    setSimulation(null); // Reset preview on action update to drive verification
  };

  if (isLoading) {
    return (
      <div style={{ padding: "40px", width: "100%" }}>
        <LoadingState message="Retrieving compliance telemetry from agent registries..." />
      </div>
    );
  }

  return (
    <ConsolePage>

      {/* 5. Module Header Integration */}
      <ModuleHeader
        title="Device Control & Security Compliance"
        eyebrow="Endpoint Protection Module"
        icon={ShieldCheck}
        status={policy.status}
        policyVersion={policy.policy_version}
        policyLastSynced={policy.last_updated}
        onRefresh={handleSyncPolicy}
        isRefreshing={isSyncing}
        quickActions={[
          {
            label: "Initiate Sweep Scan",
            icon: RefreshCw,
            onClick: () => {
              setSuccess("Initiated device validation sweep query across scoped agents.");
            },
            variant: "secondary",
            disabled: isWorking,
          },
        ]}
      />

      {/* Notifications Row */}
      {error && <ErrorBanner message={error} />}
      {success && <SuccessBanner message={success} />}

      <MetricGrid
        ariaLabel="Compliance Summary Statistics"
        items={[
          { label: "Module Mode", value: "Enforcement Tier Active", icon: <ShieldCheck size={20} />, color: "var(--accent)" },
          { label: "Active Warnings", value: `${detections.filter((d) => d.status === "new").length} Issues Pending`, icon: <AlertTriangle size={20} />, color: "var(--warning)" },
          { label: "Approval Workflow", value: policy.approval_required ? "MSP Multi-Gate Gatekeeper" : "Automatic Execution", icon: <Clock size={20} />, color: "var(--muted)" },
        ]}
      />

      {/* 6. Three-Panel Layout (Work Area) */}
      <section className="panelWorkspace" aria-label="Device Rules Management Core Console">
        {/* Panel A: Detection Alarm List Queue */}
        <DetectionTable
          detections={detections}
          selectedId={selectedId}
          onSelect={(d) => {
            setSelectedId(d.id);
            handleActionChange(d.recommended_action);
          }}
          isLoading={isLoading}
        />

        {/* Panel B: Analytical Side panel Context */}
        <DetailPanel detection={selectedDetection} />

        {/* Panel C: Decision Action Hub & Staging Terminal */}
        <ActionStagingPanel
          detection={selectedDetection}
          selectedAction={selectedAction}
          simulation={simulation}
          stagedActions={stagedActions}
          isWorking={isWorking}
          onActionChange={handleActionChange}
          onSimulate={simulateAction}
          onStage={() => stageAction()}
          availableActions={[
            { value: "quarantine_drive", label: "Quarantine & Interdict USB device", destructive: true },
            { value: "re_enable_encryption", label: "Re-enable Boot Volume Encryption", destructive: false },
            { value: "disable_host_nic", label: "Isolate Endpoint from Router Bridge", destructive: true },
            { value: "dismiss_alert", label: "Dismiss compliance warning manually", destructive: false },
          ]}
        />
      </section>

      {/* Policy Exclusions & Timeline Grid Section */}
      <section
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))",
          gap: "16px",
          marginTop: "24px",
        }}
      >
        {/* Exclusion Manager */}
        <article className="panel">
          <div className="panelHeader" style={{ borderBottom: "1px solid var(--line)", paddingBottom: "10px", marginBottom: "12px" }}>
            <h2 style={{ fontSize: "14px", margin: 0 }}>Approved Global Exclusions</h2>
            <span style={{ fontSize: "11px", color: "var(--muted)" }}>No local overrides are applied if matched here</span>
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: "8px", fontSize: "12px" }}>
            <div style={{ display: "flex", justifyContent: "space-between", background: "rgba(11, 107, 87, 0.01)", padding: "8px", borderRadius: "6px", border: "1px solid var(--line)" }}>
              <code>USB-VID_0951&PID_1666</code>
              <span style={{ color: "var(--muted)" }}>Corporate Kingston Key Standard</span>
            </div>
            <div style={{ display: "flex", justifyContent: "space-between", background: "rgba(11, 107, 87, 0.01)", padding: "8px", borderRadius: "6px", border: "1px solid var(--line)" }}>
              <code>C:\Program Files\BackupAgent\*</code>
              <span style={{ color: "var(--muted)" }}>Global Backup Service Excludes</span>
            </div>
          </div>
        </article>

        {/* Global Policy Config Toggles */}
        <article className="panel">
          <div className="panelHeader" style={{ borderBottom: "1px solid var(--line)", paddingBottom: "10px", marginBottom: "12px" }}>
            <h2 style={{ fontSize: "14px", margin: 0 }}>Policy Engine Config Map</h2>
            <span style={{ fontSize: "11px", color: "var(--muted)" }}>Effective Policy Engine parameters</span>
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: "10px" }}>
            {Object.entries(policy.controls).map(([key, enabled]) => (
              <label key={key} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", cursor: "pointer", fontSize: "12px" }}>
                <span>{key.replaceAll("_", " ").toUpperCase()}</span>
                <input type="checkbox" checked={enabled} readOnly style={{ accentColor: "var(--accent)", cursor: "not-allowed" }} />
              </label>
            ))}
          </div>
        </article>
      </section>

      {/* Destructive Action Modal Backdrop */}
      {confirmRequest && (
        <div
          style={{
            position: "fixed",
            inset: 0,
            background: "rgba(19, 32, 27, 0.6)",
            backdropFilter: "blur(2px)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            zIndex: 1000,
          }}
          role="presentation"
        >
          <section
            className="accountModal"
            role="dialog"
            aria-modal="true"
            aria-label="Confirm Impact-heavy Action"
            style={{
              background: "#fffef9",
              padding: "24px",
              borderRadius: "12px",
              border: "1px solid var(--line)",
              maxWidth: "460px",
              width: "100%",
              boxShadow: "0 10px 25px -5px rgba(0, 0, 0, 0.1), 0 8px 10px -6px rgba(0, 0, 0, 0.1)",
            }}
          >
            <h3 style={{ margin: "0 0 10px 0", fontSize: "18px", color: "var(--warning)" }}>Confirm Destruction Level response</h3>
            <p style={{ margin: "0 0 20px 0", fontSize: "13px", color: "var(--muted)", lineHeight: 1.5 }}>
              You are staging an action (<strong>{confirmRequest.action.replaceAll("_", " ")}</strong>) with high-density system modification impact metrics on endpoint <strong>{confirmRequest.detection.endpoint_name}</strong>. This can disconnect system interfaces or lock mass storage channels.
            </p>
            <div style={{ display: "flex", justifyContent: "flex-end", gap: "12px" }}>
              <button
                type="button"
                className="btnSecondary"
                onClick={() => setConfirmRequest(null)}
                style={{ cursor: "pointer" }}
              >
                Abrupt Cancel
              </button>
              <button
                type="button"
                className="btnPrimary"
                onClick={() => stageAction(true)}
                style={{ cursor: "pointer" }}
              >
                Confirm & Dispatch Stage
              </button>
            </div>
          </section>
        </div>
      )}
    </ConsolePage>
  );
}

import React, { useState, useEffect } from "react";
import {
  Archive,
  AlertTriangle,
  CheckCircle,
  FileText,
  Mail,
  Terminal,
  ShieldCheck,
} from "lucide-react";
import { ModuleHeader } from "../components/protection/ModuleHeader";
import { DetectionTable } from "../components/protection/DetectionTable";
import { DetailPanel } from "../components/protection/DetailPanel";
import { ActionStagingPanel } from "../components/protection/ActionStagingPanel";
import { LoadingState } from "../components/protection/EmptyState";
import {
  Detection,
  StagedAction,
  SimulationPreview,
  EffectivePolicy,
} from "../components/protection/types";
import { ConsolePage, ErrorBanner, MetricGrid, SuccessBanner } from "../components";
import { apiGet, apiPost, type MeResponse } from "../api";

export type QuarantineItemKind = "file" | "email" | "process" | "network_connection";

export interface QuarantineItem {
  id: string;
  customer_id?: string | null;
  hostname: string;
  kind: QuarantineItemKind;
  name: string;
  path?: string | null;
  hash?: string | null;
  quarantine_reason: string;
  severity: "low" | "medium" | "high" | "critical";
  status: "quarantined" | "restore_requested" | "restored" | "deleted";
  quarantined_at: string;
  quarantined_by: string;
  detection_id?: string | null;
}

const KIND_ICON: Record<QuarantineItemKind, React.ReactNode> = {
  file: <FileText size={14} />,
  email: <Mail size={14} />,
  process: <Terminal size={14} />,
  network_connection: <ShieldCheck size={14} />,
};

const KIND_LABEL: Record<QuarantineItemKind, string> = {
  file: "File",
  email: "Email",
  process: "Process",
  network_connection: "Network Connection",
};

const DEMO_ITEMS: QuarantineItem[] = [
  {
    id: "q-001",
    customer_id: null,
    hostname: "WIN-WORK-042",
    kind: "file",
    name: "invoice_Q1_2024.exe",
    path: "C:\\Users\\jdoe\\Downloads\\invoice_Q1_2024.exe",
    hash: "a3f8b1c2d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0",
    quarantine_reason: "Trojan.GenericKD.46832741 — confidence 98%",
    severity: "critical",
    status: "quarantined",
    quarantined_at: new Date(Date.now() - 3600000 * 2).toISOString(),
    quarantined_by: "Aetherix Agent v1.4.2",
    detection_id: "alert-abc-123",
  },
  {
    id: "q-002",
    customer_id: null,
    hostname: "WIN-WORK-017",
    kind: "email",
    name: "Urgent: Account Verification Required",
    path: null,
    hash: null,
    quarantine_reason: "Phishing email — credential harvesting link detected",
    severity: "high",
    status: "quarantined",
    quarantined_at: new Date(Date.now() - 3600000 * 5).toISOString(),
    quarantined_by: "DLP Policy v2",
    detection_id: null,
  },
  {
    id: "q-003",
    customer_id: null,
    hostname: "LINUX-SRV-08",
    kind: "process",
    name: "cryptominer64",
    path: "/tmp/.hidden/cryptominer64",
    hash: "b4c9d2e3f1a0b1c2d3e4f5a6b7c8d9e0f1a2b3c4d5e6f7a8b9c0d1e2f3a4b5",
    quarantine_reason: "Cryptominer binary — CPU abuse detected",
    severity: "high",
    status: "quarantined",
    quarantined_at: new Date(Date.now() - 3600000 * 12).toISOString(),
    quarantined_by: "Aetherix Agent v1.4.1",
    detection_id: "alert-def-456",
  },
  {
    id: "q-004",
    customer_id: null,
    hostname: "WIN-WORK-001",
    kind: "file",
    name: "report_template.docm",
    path: "C:\\Users\\ksmith\\Documents\\report_template.docm",
    hash: "c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5",
    quarantine_reason: "Macro-enabled document — suspicious auto-open macro",
    severity: "medium",
    status: "restore_requested",
    quarantined_at: new Date(Date.now() - 86400000).toISOString(),
    quarantined_by: "Aetherix Agent v1.4.2",
    detection_id: null,
  },
];

export function QuarantinePage({ me }: { me: MeResponse }) {
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  const [policy, setPolicy] = useState<EffectivePolicy>({
    policy_version: "v2.10.4",
    last_updated: new Date(Date.now() - 3600000).toISOString(),
    status: "protected",
    approval_required: true,
    controls: {
      quarantine_auto: true,
      quarantine_restore_approval: true,
      quarantine_audit_trail: true,
    },
  });

  const [items, setItems] = useState<QuarantineItem[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [selectedAction, setSelectedAction] = useState<string>("confirm_quarantine");
  const [simulation, setSimulation] = useState<SimulationPreview | null>(null);
  const [stagedActions, setStagedActions] = useState<StagedAction[]>([]);
  const [isWorking, setIsWorking] = useState(false);

  const detections: Detection[] = items.map((item) => ({
    id: item.id,
    customer_id: item.customer_id,
    endpoint_id: item.hostname,
    endpoint_name: item.hostname,
    title: item.name,
    source: `Quarantine: ${KIND_LABEL[item.kind]}`,
    description: item.quarantine_reason,
    risk_score:
      item.severity === "critical" ? 95 : item.severity === "high" ? 75 : item.severity === "medium" ? 45 : 20,
    risk_band: item.severity,
    confidence: 90,
    recommended_action:
      item.status === "restore_requested" ? "approve_restore" : item.status === "quarantined" ? "confirm_quarantine" : "no_action",
    status:
      item.status === "restored" || item.status === "deleted" ? "resolved" : item.status === "restore_requested" ? "staged" : "investigating",
    created_at: item.quarantined_at,
    context: {
      user: item.quarantined_by,
      command_line: [item.path, item.hash].filter(Boolean).join(" · ") || item.name,
      mitre_techniques: item.kind === "file" ? [{ id: "T1204.002", name: "Malicious File", tactic: "Execution" }] : [],
    },
  }));

  const selectedDetection = detections.find((d) => d.id === selectedId) ?? null;
  const selectedItem = items.find((i) => i.id === selectedId) ?? null;

  useEffect(() => {
    async function load() {
      try {
        const customerId = me.scope.customer_ids[0];
        const url = customerId ? `/quarantine?customer_id=${customerId}` : `/quarantine`;
        const data = await apiGet<QuarantineItem[]>(url);
        setItems(data);
        if (data.length > 0) {
          setSelectedId(data[0].id);
          setSelectedAction(data[0].status === "restore_requested" ? "approve_restore" : "confirm_quarantine");
        }
      } catch {
        setItems(DEMO_ITEMS);
        setSelectedId(DEMO_ITEMS[0].id);
        setSelectedAction("confirm_quarantine");
      } finally {
        setIsLoading(false);
      }
    }
    void load();
  }, [me]);

  const handleSyncPolicy = async () => {
    setIsSyncing(true);
    try {
      await new Promise((r) => setTimeout(r, 600));
      setPolicy((prev) => ({ ...prev, last_updated: new Date().toISOString() }));
      setSuccess("Quarantine policies synced.");
    } catch {
      setError("Sync failed.");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleSimulate = async () => {
    if (!selectedItem) return;
    setIsWorking(true);
    try {
      await apiPost(`/quarantine/${selectedItem.id}/simulate`, { action: selectedAction });
    } catch {
      const isRestore = selectedAction === "approve_restore" || selectedAction === "request_restore";
      const sim: SimulationPreview = {
        id: `sim-q-${selectedItem.id}-${Date.now()}`,
        detection_id: selectedItem.id,
        action: selectedAction,
        destructive: selectedAction === "delete_permanently",
        approval_required: policy.approval_required,
        affected_systems: 1,
        estimated_impact: [
          isRestore
            ? `Restoring ${KIND_LABEL[selectedItem.kind]}: ${selectedItem.name}`
            : `${selectedAction === "delete_permanently" ? "Permanently deleting" : "Confirming quarantine for"}: ${selectedItem.name}`,
          `Endpoint: ${selectedItem.hostname}`,
          isRestore
            ? `The item will be restored to its original location. Original threat risk remains — confirm with operator.`
            : `Item is isolated in the quarantine store. No further execution possible.`,
        ],
        evidence_controls: ["iso27001-2022:A.8.7", "nist-csf-2.0:RS.MI"],
        created_at: new Date().toISOString(),
      };
      setSimulation(sim);
      setSuccess("Simulation complete.");
    } finally {
      setIsWorking(false);
    }
  };

  const handleStage = async () => {
    if (!selectedItem) return;
    setIsWorking(true);
    const optimistic: StagedAction = {
      id: `staged-q-${Date.now()}`,
      detection_id: selectedItem.id,
      action: selectedAction,
      status: policy.approval_required ? "awaiting_approval" : "queued",
      approval_required: policy.approval_required,
      requested_by: me.account.email,
      created_at: new Date().toISOString(),
      note: `Quarantine action staged: ${selectedAction}`,
    };
    setStagedActions((prev) => [optimistic, ...prev]);
    try {
      await apiPost(`/quarantine/${selectedItem.id}/action`, { action: selectedAction });
    } catch {
      // offline fallback — update state optimistically
    }
    const nextStatus: QuarantineItem["status"] =
      selectedAction === "approve_restore" || selectedAction === "request_restore"
        ? "restore_requested"
        : selectedAction === "delete_permanently"
        ? "deleted"
        : "quarantined";
    setItems((prev) => prev.map((i) => (i.id === selectedItem.id ? { ...i, status: nextStatus } : i)));
    setSuccess(`Action staged: ${selectedAction} on ${selectedItem.name}`);
    setIsWorking(false);
  };

  const quarantined = items.filter((i) => i.status === "quarantined").length;
  const restoreRequested = items.filter((i) => i.status === "restore_requested").length;
  const resolved = items.filter((i) => i.status === "restored" || i.status === "deleted").length;

  if (isLoading) {
    return (
      <div style={{ padding: "40px", width: "100%" }}>
        <LoadingState message="Loading quarantine store…" />
      </div>
    );
  }

  return (
    <ConsolePage>
      <ModuleHeader
        title="Quarantine"
        eyebrow="Containment"
        icon={Archive}
        status={policy.status}
        policyVersion={policy.policy_version}
        policyLastSynced={policy.last_updated}
        onRefresh={handleSyncPolicy}
        isRefreshing={isSyncing}
        quickActions={[]}
      />

      {error && <ErrorBanner message={error} />}
      {success && <SuccessBanner message={success} />}

      <MetricGrid
        ariaLabel="Quarantine Metrics"
        items={[
          { label: "Quarantined", value: quarantined, icon: <Archive size={18} />, color: "var(--danger)" },
          { label: "Restore Requested", value: restoreRequested, icon: <AlertTriangle size={18} />, color: "var(--warning)" },
          { label: "Resolved", value: resolved, icon: <CheckCircle size={18} />, color: "var(--success)" },
          { label: "Files", value: items.filter((i) => i.kind === "file").length, icon: <FileText size={18} />, color: "var(--muted)" },
          { label: "Emails", value: items.filter((i) => i.kind === "email").length, icon: <Mail size={18} />, color: "var(--muted)" },
        ]}
      />

      <section className="panelWorkspace" aria-label="Quarantine Board">
        <DetectionTable
          detections={detections}
          selectedId={selectedId}
          onSelect={(d) => {
            setSelectedId(d.id);
            const item = items.find((i) => i.id === d.id);
            setSelectedAction(item?.status === "restore_requested" ? "approve_restore" : "confirm_quarantine");
            setSimulation(null);
          }}
          isLoading={isLoading}
        />

        <DetailPanel
          detection={selectedDetection}
          customContextRenderer={(d) => {
            const item = items.find((i) => i.id === d.id);
            if (!item) return null;
            return (
              <div className="detailStack">
                <div>
                  <h4 className="sectionKicker" style={{ margin: "0 0 8px 0" }}>
                    Quarantine Details
                  </h4>
                  <div className="kvStack">
                    {[
                      { label: "Type", value: KIND_LABEL[item.kind] },
                      { label: "Status", value: item.status.replace("_", " ") },
                      { label: "Quarantined By", value: item.quarantined_by },
                      { label: "Quarantined At", value: new Date(item.quarantined_at).toLocaleString() },
                      ...(item.path ? [{ label: "Original Path", value: item.path }] : []),
                      ...(item.hash ? [{ label: "File Hash", value: `${item.hash.slice(0, 16)}…` }] : []),
                    ].map(({ label, value }) => (
                      <div key={label} className="kvRow">
                        <span>{label}</span>
                        <strong>{value}</strong>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            );
          }}
        />

        <ActionStagingPanel
          detection={selectedDetection}
          selectedAction={selectedAction}
          simulation={simulation}
          stagedActions={stagedActions}
          isWorking={isWorking}
          onActionChange={setSelectedAction}
          onSimulate={handleSimulate}
          onStage={handleStage}
          availableActions={[
            { value: "confirm_quarantine", label: "Confirm Quarantine", destructive: false },
            { value: "request_restore", label: "Request Restore", destructive: false },
            { value: "approve_restore", label: "Approve & Restore", destructive: false },
            { value: "delete_permanently", label: "Delete Permanently", destructive: true },
          ]}
        />
      </section>
    </ConsolePage>
  );
}

